import { useState, useCallback, useRef } from 'react';
import { useAudit } from '../contexts/AuditContext';
import { useKeyPool } from '../contexts/KeyPoolContext';
import { useUI } from '../contexts/UIContext';
import { generateAnalysis } from '../services/geminiService';
import { AnalysisResult, AuditProcess } from '../types';
import { generateContentHash, runWithConcurrency } from '../utils';

// Cache structure: { [clauseId_processId_evidenceHash]: AnalysisResult }
const ANALYSIS_CACHE = new Map<string, AnalysisResult>();

export const useAuditWorkflow = () => {
    const { 
        standards, standardKey, 
        setAnalysisResult, 
        processes, privacySettings 
    } = useAudit();

    const { apiKeys, activeKeyId } = useKeyPool();
    const { showToast } = useUI();

    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState("");

    // New Visualization State
    const [progressPercent, setProgressPercent] = useState(0);
    const [analysisLogs, setAnalysisLogs] = useState<string[]>([]);

    const processedCount = useRef(0);

    const handleAnalyze = useCallback(async () => {
        if (!standardKey || processes.length === 0) {
            showToast("No processes or standard found to analyze.");
            return;
        }

        setIsAnalyzeLoading(true);
        processedCount.current = 0;
        setProgressPercent(0);
        setAnalysisLogs(["Initializing AI Audit Engine...", "Scanning process matrices..."]);

        // Short delay for UI to mount
        await new Promise(r => setTimeout(r, 500));

        try {
            const currentStd = standards[standardKey];
            const activeKeyProfile = apiKeys.find(k => k.id === activeKeyId);

            // 1. IDENTIFY WORKLOAD ACROSS ALL PROCESSES
            const queue: { process: AuditProcess, cid: string, clause: any }[] = [];

            // Helper to find clause structure
            const findClauseData = (id: string) => {
                const traverse = (list: any[]): any => {
                    for (const c of list) {
                        if (c.id === id) return c;
                        if (c.subClauses) {
                            const found = traverse(c.subClauses);
                            if (found) return found;
                        }
                    }
                    return null;
                };
                for (const g of currentStd.groups) {
                    const found = traverse(g.clauses);
                    if (found) return found;
                }
                return null;
            };

            // Loop through ALL processes
            processes.forEach(proc => {
                const procMatrix = proc.matrixData || {};

                Object.keys(procMatrix).forEach(cid => {
                    const clauseData = findClauseData(cid);
                    if (clauseData) {
                        queue.push({
                            process: proc,
                            cid: cid,
                            clause: clauseData
                        });
                    }
                });
            });

            const total = queue.length;

            if (total === 0) {
                throw new Error("No clauses mapped in any process. Please go to Planning tab to select clauses.");
            }

            setAnalysisLogs(prev => [...prev, `Found ${total} compliance checkpoints across ${processes.length} processes.`]);

            // 2. DEFINE WORKER FUNCTION (runs in parallel)
            const processItem = async ({ process, cid, clause }: { process: AuditProcess, cid: string, clause: any }) => {
                if (!clause) return null;

                const procName = process.name || "Unnamed Process";
                setCurrentAnalyzingClause(`[${procName}] ${clause.code}`);

                // Update Logs (Throttle slightly to avoid React render trashing if very fast)
                if (processedCount.current % 2 === 0 || total < 10) {
                     setAnalysisLogs(prev => {
                         const next = [...prev, `> Processing ${procName} / Clause ${clause.code}...`];
                         if (next.length > 8) return next.slice(next.length - 8); // Keep log short
                         return next;
                     });
                }

                // Data Prep
                const matrixRows = process.matrixData[cid] || [];
                const hasSpecificInput = matrixRows.some(r => r.status === 'supplied');

                // Construct specific evidence for AI Context
                let specificEvidenceForAI = "";
                let rawUserEvidence = "";

                if (hasSpecificInput) {
                    specificEvidenceForAI = matrixRows
                        .filter(r => r.status === 'supplied')
                        .map(r => `[Requirement]: ${r.requirement}\n[Evidence]: ${r.evidenceInput}`)
                        .join("\n\n");

                    rawUserEvidence = matrixRows
                        .filter(r => r.status === 'supplied')
                        .map(r => r.evidenceInput)
                        .join("\n\n");
                }

                // --- NEW INTELLIGENCE: GROUP / PDCA CONTEXT AGGREGATION ---
                // Find which Group (e.g., Plan, Do, Check) this clause belongs to
                let relatedGroupEvidence = "";
                let parentGroupName = "";

                const parentGroup = currentStd.groups.find(g => {
                    const flatten = (list: any[]): string[] => list.flatMap(x => [x.id, ...(x.subClauses ? flatten(x.subClauses) : [])]);
                    const groupIds = flatten(g.clauses);
                    return groupIds.includes(cid);
                });

                if (parentGroup) {
                    parentGroupName = parentGroup.title;
                    const relevantRows: string[] = [];

                    // Flatten all IDs in this group to find siblings/children
                    const getAllIds = (list: any[]): string[] => list.flatMap(x => [x.id, ...(x.subClauses ? getAllIds(x.subClauses) : [])]);
                    const groupIds = getAllIds(parentGroup.clauses);

                    groupIds.forEach(otherCid => {
                        if (otherCid === cid) return; // Skip self
                        const rows = process.matrixData[otherCid];
                        if (rows && rows.some(r => r.status === 'supplied')) {
                            const text = rows.filter(r => r.status === 'supplied').map(r => r.evidenceInput).join(" ");
                            if (text.trim().length > 5) {
                                // We include the code so AI knows 6.1 supports 6
                                relevantRows.push(`[Related Clause ${otherCid} Evidence]: ${text.substring(0, 600)}...`); 
                            }
                        }
                    });

                    if (relevantRows.length > 0) {
                        relatedGroupEvidence = relevantRows.join("\n");
                    }
                }
                // ---------------------------------------------------------

                // General evidence from THIS SPECIFIC PROCESS
                const procEvidence = process.evidence || "";
                const safeGeneralEvidence = procEvidence.length > 8000 ? procEvidence.substring(0, 8000) + "...(truncated)" : procEvidence;

                // Smart Evidence Composition
                const combinedEvidence = `
                ${specificEvidenceForAI ? `### DIRECT EVIDENCE (Clause ${clause.code}):\n${specificEvidenceForAI}` : '### DIRECT EVIDENCE: None specifically recorded for this exact clause number.'}

                ${relatedGroupEvidence ? `### BROADER CONTEXT (PDCA Group - ${parentGroupName}):\n(The following evidence comes from related sub-clauses or sibling clauses within the same PDCA phase. Use this to verify high-level compliance, e.g., evidence in 6.1 proves compliance for 6).\n${relatedGroupEvidence}` : ''}

                ${safeGeneralEvidence ? `### GENERAL PROCESS EVIDENCE (${procName}):\n${safeGeneralEvidence}` : ''}

                CRITICAL INSTRUCTION: 
                1. If Direct Evidence is missing, YOU MUST look at 'BROADER CONTEXT' and 'GENERAL PROCESS EVIDENCE'.
                2. Evidence found in sub-clauses (e.g., 6.1, 6.2) IS VALID evidence for the parent clause (e.g., 6). Do not mark as NC if the requirement is met in the sub-clauses.
                3. If the intent of the clause is met anywhere in this context, mark as COMPLIANT.
                `.trim();

                const tagsText = (process.evidenceTags || [])
                    .filter(t => t.clauseId === cid)
                    .map(t => `Tagged Excerpt: "${t.text}"`)
                    .join("\n");

                const fullInput = combinedEvidence + tagsText;

                // Cache Check
                const cacheKey = generateContentHash(`${cid}_${process.id}_${fullInput}_${activeKeyProfile?.activeModel}`);

                if (ANALYSIS_CACHE.has(cacheKey)) {
                    console.log(`[Cache Hit] ${procName} - Clause ${cid}`);
                    processedCount.current++;
                    setProgressPercent(Math.round((processedCount.current / total) * 100));
                    return ANALYSIS_CACHE.get(cacheKey)!;
                }

                // Call API
                try {
                    const jsonResult = await generateAnalysis(
                        { code: clause.code, title: clause.title, description: clause.description },
                        currentStd.name,
                        combinedEvidence,
                        tagsText,
                        activeKeyProfile?.key,
                        activeKeyProfile?.activeModel,
                        privacySettings.maskCompany
                    );

                    const parsed = JSON.parse(jsonResult);

                    const finalEvidence = rawUserEvidence.trim().length > 0 
                        ? rawUserEvidence 
                        : (parsed.evidence || "Analyzed based on broader context/sub-clauses.");

                    const result: AnalysisResult = {
                        clauseId: parsed.clauseId || clause.code,
                        status: parsed.status || "N_A",
                        reason: parsed.reason || "Analysis completed.",
                        reason_en: parsed.reason_en || parsed.reason, // NEW
                        reason_vi: parsed.reason_vi, // NEW
                        suggestion: parsed.suggestion || "",
                        evidence: finalEvidence, 
                        conclusion_report: parsed.conclusion_report || parsed.reason,
                        crossRefs: parsed.crossRefs || [],
                        processId: process.id,
                        processName: procName
                    };

                    // Save to Cache
                    ANALYSIS_CACHE.set(cacheKey, result);
                    processedCount.current++;

                    setProgressPercent(Math.round((processedCount.current / total) * 100));

                    return result;

                } catch (e) {
                    console.error(`Error analyzing ${cid} in ${procName}`, e);
                    setAnalysisLogs(prev => [...prev, `x Error on ${cid}: ${e.message}`]);
                    processedCount.current++; // Still count it to finish
                    setProgressPercent(Math.round((processedCount.current / total) * 100));
                    return null;
                }
            };

            // Execution
            const results = await runWithConcurrency(queue, processItem, 3);

            // Update State
            const validResults = results.filter(r => r !== null) as AnalysisResult[];

            if (validResults.length > 0) {
                setAnalysisResult(prev => {
                    const existing = prev ? [...prev] : [];

                    validResults.forEach(newResult => {
                        const idx = existing.findIndex(e => e.clauseId === newResult.clauseId && e.processId === newResult.processId);
                        if (idx >= 0) {
                            existing[idx] = newResult;
                        } else {
                            existing.push(newResult);
                        }
                    });

                    return existing.sort((a, b) => {
                        const clauseCompare = a.clauseId.localeCompare(b.clauseId, undefined, { numeric: true });
                        if (clauseCompare !== 0) return clauseCompare;
                        return (a.processName || "").localeCompare(b.processName || "");
                    });
                });

                setAnalysisLogs(prev => [...prev, "Synthesis Complete. Rendering Results..."]);
                await new Promise(r => setTimeout(r, 600)); // Let user see 100%
                showToast(`Success! Updated ${validResults.length} findings.`);
            } else {
                showToast("Analysis finished but returned no valid results.");
            }

        } catch (error: any) {
            console.error("Analysis Workflow Error", error);
            setAnalysisLogs(prev => [...prev, `CRITICAL ERROR: ${error.message}`]);
            showToast("Failed: " + error.message);
            await new Promise(r => setTimeout(r, 2000)); // Wait so user sees error
        } finally {
            setIsAnalyzeLoading(false);
            setCurrentAnalyzingClause("");
        }
    }, [standardKey, processes, apiKeys, activeKeyId, privacySettings, standards]);

    return { 
        handleAnalyze, 
        isAnalyzeLoading, 
        currentAnalyzingClause,
        progressPercent,
        analysisLogs
    };
};

import React, { useState, useEffect, useMemo, Suspense } from 'react';
import { AuditProvider, useAudit } from './contexts/AuditContext';
import { UIProvider, useUI } from './contexts/UIContext';
import { KeyPoolProvider, useKeyPool } from './contexts/KeyPoolContext';
import { MainLayout } from './components/layout/MainLayout';
import { TabNavigation } from './components/TabNavigation';
// Lazy Load Views
import { AINeuralLoader } from './components/ui/Loaders';
import ReferenceClauseModal from './components/ReferenceClauseModal';
import { SettingsModal } from './components/modals/SettingsModal';
import { AddStandardModal } from './components/modals/AddStandardModal';
import { ExportProgressModal } from './components/modals/ExportProgressModal';
import { Icon } from './components/UI';
import { TABS_CONFIG } from './constants';
import { useAutoSave } from './hooks/useAutoSave';
import { UploadedFile, FindingsViewMode, MatrixRow } from './types'; 
import { processSourceFile } from './utils';

// New Custom Hooks
import { useAuditWorkflow } from './hooks/useAuditWorkflow';
import { useReportGenerator } from './hooks/useReportGenerator';
import { useExportManager } from './hooks/useExportManager';
import { useKeyboardNavigation } from './hooks/useKeyboardNavigation';

// Lazy Components
const EvidenceView = React.lazy(() => import('./components/views/EvidenceView').then(module => ({ default: module.EvidenceView })));
const FindingsView = React.lazy(() => import('./components/views/FindingsView').then(module => ({ default: module.FindingsView })));
const ReportView = React.lazy(() => import('./components/views/ReportView').then(module => ({ default: module.ReportView })));
const PlanningView = React.lazy(() => import('./components/views/PlanningView').then(module => ({ default: module.PlanningView })));

const AppContent = () => {
    const [layoutMode, setLayoutMode] = useState('planning'); 

    // Enable Global Keyboard Navigation (Arrow Keys)
    useKeyboardNavigation();

    // Contexts
    const { isSidebarOpen, sidebarWidth, showToast, modals, toggleModal, setSidebarOpen } = useUI();
    const { 
        evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
        selectedClauses, standards, standardKey, auditInfo,
        setKnowledgeData, analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings,
        finalReportText, setFinalReportText, resetSession, restoreSession,
        addCustomStandard, setStandardKey, activeProcessId, processes, privacySettings
    } = useAudit();

    const { apiKeys, addKey, deleteKey, refreshKeyStatus, activeKeyId, isCheckingKey, isAutoCheckEnabled, toggleAutoCheck } = useKeyPool();
    const { lastSavedTime, isSaving, createManualBackup } = useAutoSave();

    // Local UI State
    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);
    const [referenceState, setReferenceState] = useState({ isOpen: false, clause: null, fullText: {en:"", vi:""}, isLoading: false });
    const [newKeyInput, setNewKeyInput] = useState(""); 

    // View Persistence
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');
    const [focusedFindingIndex, setFocusedFindingIndex] = useState(0);
    const [evidenceLanguage, setEvidenceLanguage] = useState<'en' | 'vi'>('en');
    const [notesLanguage, setNotesLanguage] = useState<'en' | 'vi'>('en');
    const [exportLanguage, setExportLanguage] = useState<'en' | 'vi'>('en');

    // --- INTEGRATE HOOKS ---
    const { 
        handleAnalyze, isAnalyzeLoading, currentAnalyzingClause, 
        progressPercent, analysisLogs 
    } = useAuditWorkflow();

    const { 
        isReportLoading, reportLoadingMessage, reportTemplateName, isTemplateProcessing,
        handleTemplateUpload, handleGenerateReport, generationLogs, progressPercent: reportProgress
    } = useReportGenerator(exportLanguage);
    const { 
        handleExport, exportState, setExportState, 
        rescueKey, setRescueKey, handleResumeExport, isRescuing, handleSkipExportChunk 
    } = useExportManager();

    // Event Listeners
    useEffect(() => {
        const handleRef = (e: CustomEvent) => setReferenceState({ isOpen: true, clause: e.detail, fullText: {en:"", vi:""}, isLoading: true });
        const handleRefUpdate = (e: CustomEvent) => setReferenceState(prev => ({ ...prev, fullText: e.detail, isLoading: false }));
        const handleSwitch = (e: CustomEvent) => { if (e.detail) setLayoutMode(e.detail); };

        window.addEventListener('OPEN_REFERENCE', handleRef as any);
        window.addEventListener('UPDATE_REFERENCE_CONTENT', handleRefUpdate as any);
        window.addEventListener('SWITCH_LAYOUT', handleSwitch as any);
        return () => {
            window.removeEventListener('OPEN_REFERENCE', handleRef as any);
            window.removeEventListener('UPDATE_REFERENCE_CONTENT', handleRefUpdate as any);
            window.removeEventListener('SWITCH_LAYOUT', handleSwitch as any);
        };
    }, []);

    // Helper: Dynamic Styles
    const liquidColorClass = useMemo(() => {
        const config = TABS_CONFIG.find(t => t.id === layoutMode);
        return config ? `${config.colorClass} ${config.borderClass}` : 'bg-slate-500 border-slate-600';
    }, [layoutMode]);

    const themeStyles = useMemo(() => {
        switch (layoutMode) {
            case 'planning': return 'selection:bg-orange-200 selection:text-orange-900 dark:selection:bg-orange-900 dark:selection:text-orange-100 bg-orange-50/80 dark:bg-orange-950/20';
            case 'evidence': return 'selection:bg-blue-200 selection:text-blue-900 dark:selection:bg-blue-900 dark:selection:text-blue-100 bg-blue-50/80 dark:bg-blue-950/20';
            case 'findings': return 'selection:bg-purple-200 selection:text-purple-900 dark:selection:bg-purple-900 dark:selection:text-purple-100 bg-purple-50/80 dark:bg-purple-950/20';
            case 'report': return 'selection:bg-emerald-200 selection:text-emerald-900 dark:selection:bg-emerald-900 dark:selection:text-emerald-100 bg-emerald-50/80 dark:bg-emerald-950/20';
            default: return 'selection:bg-indigo-200 selection:text-indigo-900';
        }
    }, [layoutMode]);

    const currentTabConfig = TABS_CONFIG.find(t => t.id === layoutMode) || TABS_CONFIG[0];
    const showProcessBlocker = (!activeProcessId || processes.length === 0) && layoutMode !== 'planning';

    const handleAddKeyWrapper = async () => {
        const status = await addKey(newKeyInput);
        if (status === 'valid') { setNewKeyInput(""); showToast("Success: API Key is Active"); } 
        else if (status === 'quota_exceeded') { setNewKeyInput(""); showToast("Added: Key Quota Exhausted"); } 
        else if (status === 'duplicate') showToast("Info: Key already exists"); 
        else showToast("Failed: Invalid API Key or Network Error");
    };

    const isReadyForAnalysis = useMemo(() => {
        if (!standardKey || !activeProcessId || isAnalyzeLoading) return false;
        // Explicitly type the iterator to MatrixRow[] to avoid 'unknown' error
        const hasMatrixData = Object.values(matrixData).some((rows: MatrixRow[]) => rows.some(r => r.status === 'supplied'));
        const hasGlobalEvidence = evidence && evidence.trim().length > 10;
        return hasMatrixData || hasGlobalEvidence;
    }, [standardKey, activeProcessId, matrixData, evidence, isAnalyzeLoading]);

    // Wrap Analyze with Auto-Switch
    const handleAnalyzeClick = async () => {
        setLayoutMode('findings'); // Auto-switch to see progress
        await handleAnalyze();
    };

    return (
        <MainLayout commandActions={[]} onRestoreSnapshot={restoreSession}>
            {/* Top Bar - Color Synced Border Top */}
            <div className={`flex-shrink-0 px-4 md:px-6 py-3 border-b border-gray-200 dark:border-slate-800 transition-colors duration-500 ease-fluid flex justify-between items-center gap-3 border-t-4 ${currentTabConfig.borderClass} ${liquidColorClass.split(' ')[0].replace('bg-', 'bg-opacity-10 ')}`}>
                <div className="flex-1 min-w-0">
                    <TabNavigation 
                        layoutMode={layoutMode} 
                        setLayoutMode={setLayoutMode}
                        isSidebarOpen={isSidebarOpen}
                        sidebarWidth={sidebarWidth}
                    />
                </div>
                <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                    <button onClick={() => toggleModal('recall', true)} className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all border shadow-sm ${lastSavedTime ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600' : 'bg-white dark:bg-slate-800 text-slate-500'}`}>
                        <div className="relative">
                            <Icon name="History" size={18}/>
                            {lastSavedTime && <span className="absolute -top-1 -right-1 flex h-2.5 w-2.5"><span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${isSaving ? 'bg-red-500' : 'bg-emerald-500'}`}></span></span>}
                        </div>
                        <span className="hidden xl:inline text-xs font-bold">Recall</span>
                    </button>
                    <button onClick={() => { if(confirm("Start New Session?")) { createManualBackup(); resetSession(); showToast("Session Reset."); }}} className="h-10 px-4 bg-amber-50 dark:bg-amber-950/30 text-amber-600 border border-amber-200 rounded-xl flex items-center justify-center gap-2 hover:bg-amber-100 transition-all shadow-sm">
                        <Icon name="Session4_FilePlus" size={18}/>
                        <span className="hidden md:inline text-xs font-bold">New</span>
                    </button>
                </div>
            </div>

            {/* MAIN CONTENT WRAPPER */}
            <div className={`flex-1 overflow-hidden relative p-2 md:p-4 transition-colors duration-500 ease-fluid ${themeStyles}`}>
                {showProcessBlocker && (
                    <div className="absolute inset-0 z-50 bg-white/80 dark:bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center animate-in fade-in">
                        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-floating border border-indigo-100 dark:border-indigo-900 max-w-md text-center">
                            <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/50 rounded-full flex items-center justify-center mx-auto mb-4 text-indigo-600"><Icon name="Session11_GridAdd" size={32} /></div>
                            <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">Process Required</h3>
                            <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 leading-relaxed">Define at least one <strong>Process</strong> to begin evidence collection.</p>
                            <div className="flex gap-3 justify-center">
                                <button onClick={() => setLayoutMode('planning')} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg transition-transform active:scale-95">Go to Planning</button>
                            </div>
                        </div>
                    </div>
                )}

                <Suspense fallback={<AINeuralLoader message="Loading View..." />}>
                    {layoutMode === 'planning' && <PlanningView />}

                    {layoutMode === 'evidence' && (
                        <EvidenceView
                            key={activeProcessId} // Forces a fresh mount when switching processes to prevent state bleeding
                            evidence={evidence} setEvidence={setEvidence}
                            uploadedFiles={uploadedFiles} setUploadedFiles={setUploadedFiles}
                            onOcrProcess={() => {}} isOcrLoading={false}
                            onAnalyze={handleAnalyzeClick} 
                            isReadyForAnalysis={isReadyForAnalysis} 
                            isAnalyzeLoading={isAnalyzeLoading} 
                            analyzeTooltip="Run AI Analysis"
                            onExport={handleExport} 
                            evidenceLanguage={evidenceLanguage} setEvidenceLanguage={setEvidenceLanguage}
                            textareaRef={{ current: null }} tags={evidenceTags} onAddTag={addEvidenceTag}
                            selectedClauses={selectedClauses} standards={standards} standardKey={standardKey}
                            matrixData={matrixData} setMatrixData={setMatrixData}
                        />
                    )}

                    {layoutMode === 'findings' && (
                        <FindingsView
                            analysisResult={analysisResult} setAnalysisResult={setAnalysisResult}
                            selectedFindings={selectedFindings} setSelectedFindings={setSelectedFindings}
                            isAnalyzeLoading={isAnalyzeLoading} loadingMessage="Scanning Matrix Evidence..." 
                            currentAnalyzingClause={currentAnalyzingClause}
                            viewMode={findingsViewMode} setViewMode={setFindingsViewMode}
                            focusedFindingIndex={focusedFindingIndex} setFocusedFindingIndex={setFocusedFindingIndex}
                            onExport={handleExport} 
                            notesLanguage={notesLanguage} setNotesLanguage={setNotesLanguage}
                            progressPercent={progressPercent}
                            analysisLogs={analysisLogs}
                        />
                    )}

                    {layoutMode === 'report' && (
                        <ReportView
                            finalReportText={finalReportText} setFinalReportText={setFinalReportText}
                            isReportLoading={isReportLoading} loadingMessage={reportLoadingMessage}
                            templateFileName={reportTemplateName}
                            isTemplateProcessing={isTemplateProcessing}
                            handleTemplateUpload={handleTemplateUpload} 
                            handleGenerateReport={handleGenerateReport}
                            isReadyToSynthesize={!!analysisResult && analysisResult.length > 0} 
                            onExport={handleExport} 
                            exportLanguage={exportLanguage} setExportLanguage={setExportLanguage}
                            analysisResult={analysisResult} // Pass results for Stage Builder
                            generationLogs={generationLogs}
                            progressPercent={reportProgress}
                            selectedFindings={selectedFindings} // PASS SELECTION STATE
                        />
                    )}
                </Suspense>
            </div>

            {/* Modals */}
            <SettingsModal 
                isOpen={modals.settings} onClose={() => toggleModal('settings', false)} 
                apiKeys={apiKeys} newKeyInput={newKeyInput} setNewKeyInput={setNewKeyInput} 
                isCheckingKey={isCheckingKey} handleAddKey={handleAddKeyWrapper}
                activeKeyId={activeKeyId} editingKeyId={null} editLabelInput="" setEditLabelInput={() => {}}
                handleSaveLabel={() => {}} handleStartEdit={() => {}} handleRefreshStatus={refreshKeyStatus} handleDeleteKey={deleteKey}
                isAutoCheckEnabled={isAutoCheckEnabled} toggleAutoCheck={toggleAutoCheck}
            />

            <AddStandardModal
                isOpen={modals.addStandard} onClose={() => toggleModal('addStandard', false)}
                onAdd={async (name, file) => {
                    toggleModal('addStandard', false);
                    const newKey = `CUSTOM_${Date.now()}`;
                    if(file) { const text = await processSourceFile(file); setKnowledgeData(text, file.name); }
                    addCustomStandard(newKey, { name, description: "Custom", groups: [] });
                    setStandardKey(newKey);
                }}
            />

            <ReferenceClauseModal
                isOpen={referenceState.isOpen} onClose={() => setReferenceState(prev => ({...prev, isOpen: false}))}
                clause={referenceState.clause} standardName={standards[standardKey]?.name || ""}
                fullText={referenceState.fullText} isLoading={referenceState.isLoading}
                onInsert={(text) => setEvidence(prev => prev + "\n" + text)}
            />

            <ExportProgressModal 
                exportState={exportState} setExportState={setExportState}
                rescueKey={rescueKey} setRescueKey={setRescueKey}
                handleResumeExport={handleResumeExport} isRescuing={isRescuing}
                onClose={() => setExportState(prev => ({ ...prev, isOpen: false }))}
                onSkip={handleSkipExportChunk}
            />
        </MainLayout>
    );
};

export default function App() {
    return (
        <UIProvider>
            <KeyPoolProvider>
                <AuditProvider>
                    <AppContent />
                </AuditProvider>
            </KeyPoolProvider>
        </UIProvider>
    );
}

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { Icon } from '../UI';
import { AnalysisResult, FindingStatus, FindingsViewMode } from '../../types';
import { TABS_CONFIG } from '../../constants';
import { performShadowReview, generateAnalysis, translateChunk } from '../../services/geminiService';
import { useKeyPool } from '../../contexts/KeyPoolContext';
import { useUI } from '../../contexts/UIContext';
import { useAudit } from '../../contexts/AuditContext';

interface FindingsViewProps {
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    isAnalyzeLoading: boolean;
    loadingMessage: string;
    currentAnalyzingClause: string;
    viewMode: FindingsViewMode;
    setViewMode: (mode: FindingsViewMode) => void;
    focusedFindingIndex: number;
    setFocusedFindingIndex: (index: number) => void;
    onExport: (type: 'notes', lang: 'en' | 'vi') => void;
    notesLanguage: 'en' | 'vi';
    setNotesLanguage: (lang: 'en' | 'vi') => void;
    progressPercent?: number; // Added
    analysisLogs?: string[]; // Added
}

export const FindingsView: React.FC<FindingsViewProps> = ({
    analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings,
    isAnalyzeLoading, loadingMessage, currentAnalyzingClause,
    viewMode, setViewMode, focusedFindingIndex, setFocusedFindingIndex,
    onExport, notesLanguage, setNotesLanguage, progressPercent = 0, analysisLogs = []
}) => {
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);
    const logsEndRef = useRef<HTMLDivElement>(null);

    // Contexts
    const { getActiveKey } = useKeyPool();
    const { showToast } = useUI();
    const { standards, standardKey, privacySettings } = useAudit();

    // Local state for Shadow Review
    const [reviewLoading, setReviewLoading] = useState<string | null>(null); // Clause ID
    const [reviews, setReviews] = useState<Record<string, string>>({});

    // Local state for Re-Analysis (Single Clause)
    const [reanalyzingId, setReanalyzingId] = useState<string | null>(null);
    const [translatingId, setTranslatingId] = useState<string | null>(null);

    // Grouping State
    const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

    // UI State for Evidence Expansion
    const [expandedEvidence, setExpandedEvidence] = useState<Record<string, boolean>>({});

    // Matrix Visibility State
    const [isMatrixCollapsed, setIsMatrixCollapsed] = useState(false);

    const themeConfig = TABS_CONFIG.find(t => t.id === 'findings')!;

    useEffect(() => {
        if (viewMode === 'list' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult?.length, viewMode]);

    // Auto-scroll logs
    useEffect(() => {
        if (isAnalyzeLoading && logsEndRef.current) {
            logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [analysisLogs, isAnalyzeLoading]);

    // Computed: Are all visible items selected?
    const isAllSelected = useMemo(() => {
        if (!analysisResult || analysisResult.length === 0) return false;
        return analysisResult.every(res => selectedFindings[res.clauseId]);
    }, [analysisResult, selectedFindings]);

    // Computed: Group Findings by Process
    const groupedFindings = useMemo((): Record<string, { finding: AnalysisResult, originalIndex: number }[]> => {
        if (!analysisResult) return {};
        const groups: Record<string, { finding: AnalysisResult, originalIndex: number }[]> = {};

        analysisResult.forEach((finding, index) => {
            const processName = finding.processName || "General Audit";
            if (!groups[processName]) {
                groups[processName] = [];
            }
            groups[processName].push({ finding, originalIndex: index });
        });

        // Sort keys to ensure consistent order
        return Object.keys(groups).sort().reduce((acc, key) => {
            acc[key] = groups[key];
            return acc;
        }, {} as typeof groups);
    }, [analysisResult]);

    const toggleGroup = (groupName: string) => {
        setCollapsedGroups(prev => {
            const next = new Set(prev);
            if (next.has(groupName)) next.delete(groupName);
            else next.add(groupName);
            return next;
        });
    };

    const handleToggleSelectAll = () => {
        if (!analysisResult) return;
        const newSelection: Record<string, boolean> = {};
        const targetState = !isAllSelected;

        analysisResult.forEach(res => {
            newSelection[res.clauseId] = targetState;
        });

        setSelectedFindings(prev => ({ ...prev, ...newSelection }));
        showToast(targetState ? "All Findings Selected" : "All Findings Deselected");
    };

    const handleUpdateFinding = (index: number, field: keyof AnalysisResult, value: string) => {
        setAnalysisResult(prev => {
            if (!prev) return null;
            const newArr = [...prev];
            newArr[index] = { ...newArr[index], [field]: value };
            return newArr;
        });
        // Auto-scroll only on status change, not text editing
        if (field === 'status' && analysisResult) {
            const nextIndex = index + 1;
            if (nextIndex < analysisResult.length && findingRefs.current[nextIndex]) {
                setTimeout(() => findingRefs.current[nextIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' }), 100);
            }
        }
    };

    const handleShadowReview = async (e: React.MouseEvent, finding: AnalysisResult) => {
        e.stopPropagation();
        const keyProfile = getActiveKey();
        if (!keyProfile) return showToast("API Key Required for Review");

        setReviewLoading(finding.clauseId);
        try {
            const critique = await performShadowReview(finding, keyProfile.key, keyProfile.activeModel);
            setReviews(prev => ({ ...prev, [finding.clauseId]: critique }));
        } catch (err) {
            showToast("Review Failed");
        } finally {
            setReviewLoading(null);
        }
    };

    // --- RE-EVALUATION LOGIC ---
    const handleReAnalyze = async (index: number, finding: AnalysisResult) => {
        const keyProfile = getActiveKey();
        if (!keyProfile) return showToast("API Key Required");
        if (!standardKey || !standards[standardKey]) return showToast("Standard context missing");

        setReanalyzingId(finding.clauseId);

        try {
            // 1. Find Clause Data
            const currentStd = standards[standardKey];
            const findClauseData = (id: string) => {
                const traverse = (list: any[]): any => {
                    for (const c of list) {
                        if (c.id === id || c.code === id) return c;
                        if (c.subClauses) {
                            const found = traverse(c.subClauses);
                            if (found) return found;
                        }
                    }
                    return null;
                };
                for (const g of currentStd.groups) {
                    const found = traverse(g.clauses);
                    if (found) return found;
                }
                return null;
            };

            const clauseData = findClauseData(finding.clauseId);
            if (!clauseData) throw new Error("Clause definition not found");

            // 2. Call AI with Updated Evidence
            const resultJson = await generateAnalysis(
                { code: clauseData.code, title: clauseData.title, description: clauseData.description },
                currentStd.name,
                finding.evidence, // Use the potentially EDITED evidence
                "", // No tags context needed for re-eval, user input is truth
                keyProfile.key,
                keyProfile.activeModel,
                privacySettings.maskCompany
            );

            const parsed = JSON.parse(resultJson);

            // 3. Update State (Merge Result)
            setAnalysisResult(prev => {
                if (!prev) return null;
                const newArr = [...prev];
                // Keep the edited evidence, update status/reason/suggestion
                newArr[index] = { 
                    ...newArr[index], 
                    status: parsed.status,
                    reason: parsed.reason,
                    reason_en: parsed.reason_en,
                    reason_vi: parsed.reason_vi,
                    suggestion: parsed.suggestion,
                    conclusion_report: parsed.conclusion_report
                };
                return newArr;
            });
            showToast("Finding Re-evaluated Successfully");

        } catch (error: any) {
            console.error(error);
            showToast("Re-evaluation Failed: " + error.message);
        } finally {
            setReanalyzingId(null);
        }
    };

    // --- INSTANT TRANSLATION LOGIC ---
    const handleTranslateReason = async (index: number, finding: AnalysisResult) => {
        const keyProfile = getActiveKey();
        if (!keyProfile) return showToast("API Key Required");

        setTranslatingId(finding.clauseId);
        try {
            const targetLang = notesLanguage;
            const textToTranslate = finding.reason || "";
            if(!textToTranslate) return;

            const translated = await translateChunk(textToTranslate, targetLang, keyProfile.key);

            setAnalysisResult(prev => {
                if (!prev) return null;
                const newArr = [...prev];
                // Save to the appropriate field
                if(targetLang === 'vi') newArr[index] = { ...newArr[index], reason_vi: translated };
                else newArr[index] = { ...newArr[index], reason_en: translated };
                return newArr;
            });
            showToast("Translation complete.");
        } catch(e) {
            showToast("Translation failed.");
        } finally {
            setTranslatingId(null);
        }
    };

    const getFindingColorStyles = (status: FindingStatus) => {
        switch (status) {
            case 'COMPLIANT': return { bg: 'bg-emerald-500', text: 'text-emerald-700 dark:text-emerald-300', pill: 'bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300', border: 'border-emerald-500' };
            case 'NC_MAJOR': return { bg: 'bg-red-600', text: 'text-red-700 dark:text-red-300', pill: 'bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-300', border: 'border-red-600' };
            case 'NC_MINOR': return { bg: 'bg-orange-500', text: 'text-orange-700 dark:text-orange-300', pill: 'bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-400', border: 'border-orange-500' };
            case 'OFI': return { bg: 'bg-blue-500', text: 'text-blue-700 dark:text-blue-300', pill: 'bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300', border: 'border-blue-500' };
            default: return { bg: 'bg-slate-500', text: 'text-slate-600', pill: 'bg-slate-100 text-slate-500', border: 'border-slate-300' };
        }
    };

    const renderFindingCard = (res: AnalysisResult, idx: number, isCondensed = false) => {
        const styles = getFindingColorStyles(res.status as FindingStatus);
        const reviewText = reviews[res.clauseId];
        const isReviewing = reviewLoading === res.clauseId;
        const isReanalyzing = reanalyzingId === res.clauseId;
        const isTranslating = translatingId === res.clauseId;
        const isEvidenceExpanded = expandedEvidence[res.clauseId] || false;

        // Determine displayed reason text based on language preference
        let displayReason = res.reason;
        const hasVi = !!res.reason_vi;
        const hasEn = !!res.reason_en;

        if (notesLanguage === 'vi') {
            displayReason = res.reason_vi || res.reason; 
        } else {
            displayReason = res.reason_en || res.reason;
        }

        // Check if we need to offer translation (e.g. user wants VI but we only have default/EN)
        const showTranslateBtn = (notesLanguage === 'vi' && !hasVi) || (notesLanguage === 'en' && !hasEn && !res.reason.match(/^[A-Za-z]/)); 

        return (
            <div
                key={idx}
                ref={!isCondensed ? el => { findingRefs.current[idx] = el; } : null}
                className={`group relative bg-white dark:bg-slate-900 rounded-2xl p-4 md:p-5 border-l-[6px] transition-all duration-300 hover:shadow-depth-lg dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05)] ${styles.border} ${selectedFindings[res.clauseId] ? 'ring-2 ring-indigo-500/20 translate-x-2' : 'hover:translate-x-1 opacity-95 hover:opacity-100'} animate-in slide-in-from-bottom-2 fade-in fill-mode-backwards`}
                style={{ animationDelay: `${idx * 50}ms` }}
                onClick={() => setSelectedFindings(prev => ({ ...prev, [res.clauseId]: !prev[res.clauseId] }))}
            >
                {/* Header Controls */}
                <div className="absolute top-4 right-4 z-10 flex gap-2">
                    <button 
                        onClick={(e) => handleShadowReview(e, res)}
                        disabled={isReviewing}
                        className={`p-1.5 rounded-full transition-all border ${reviewText ? 'bg-purple-100 text-purple-600 border-purple-200' : 'bg-gray-100 text-slate-400 hover:text-purple-600 hover:bg-purple-50 border-transparent'}`}
                        title="AI Shadow Review (Critique Finding)"
                    >
                        {isReviewing ? <Icon name="Loader" className="animate-spin" size={14}/> : <Icon name="ShieldEye" size={14}/>}
                    </button>
                    {selectedFindings[res.clauseId] ? (
                        <div className="bg-emerald-100 dark:bg-emerald-900/30 rounded-full p-1 text-emerald-600 dark:text-emerald-400">
                            <Icon name="CheckThick" size={18} />
                        </div>
                    ) : (
                        <div className="w-6 h-6 rounded-full border-2 border-gray-200 dark:border-slate-700 group-hover:border-indigo-400 transition-colors"></div>
                    )}
                </div>

                <div className="pr-12">
                    <div className="flex items-center gap-3 mb-4 flex-wrap">
                        <span className="text-xs font-black text-slate-500 dark:text-slate-400 bg-gray-100 dark:bg-slate-800 px-2 py-1 rounded-lg border border-gray-200 dark:border-slate-700">{res.clauseId}</span>
                        {res.processName && (
                            <span className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded border border-indigo-100 dark:border-indigo-800 flex items-center gap-1">
                                <Icon name="Session11_GridAdd" size={10} /> {res.processName}
                            </span>
                        )}
                        <div className="relative group/badge" onClick={e => e.stopPropagation()}>
                            <select
                                value={res.status}
                                onChange={(e) => handleUpdateFinding(idx, 'status', e.target.value)}
                                className={`appearance-none cursor-pointer text-[10px] font-black uppercase tracking-wider px-3 py-1 rounded-full ${styles.pill} border-none outline-none hover:brightness-95 text-center transition-all shadow-sm`}
                            >
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="COMPLIANT">COMPLIANT</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="NC_MINOR">MINOR NC</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="NC_MAJOR">MAJOR NC</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="OFI">OFI</option>
                            </select>
                        </div>
                    </div>

                    {/* COLLAPSIBLE EVIDENCE SECTION */}
                    <div className="mb-4 group/evidence relative">
                        {isReanalyzing && (
                            <div className="absolute inset-0 z-20 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm rounded-xl flex items-center justify-center border border-indigo-100 dark:border-indigo-900">
                                <div className="flex flex-col items-center">
                                    <Icon name="Loader" className="animate-spin text-indigo-500 mb-2" size={24}/>
                                    <span className="text-xs font-bold text-indigo-600 dark:text-indigo-400 animate-pulse">Re-evaluating based on updates...</span>
                                </div>
                            </div>
                        )}

                        <div className="bg-slate-50 dark:bg-slate-950/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800 relative transition-colors focus-within:border-indigo-300 dark:focus-within:border-indigo-700 focus-within:ring-1 focus-within:ring-indigo-500/20" onClick={e => e.stopPropagation()}>
                            <div className="flex justify-between items-center mb-2">
                                <div 
                                    className="flex items-center gap-2 cursor-pointer select-none" 
                                    onClick={() => setExpandedEvidence(prev => ({...prev, [res.clauseId]: !prev[res.clauseId]}))}
                                >
                                    <Icon name={isEvidenceExpanded ? "ChevronDown" : "ChevronRight"} size={12} className="text-indigo-500"/>
                                    <strong className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider block">Verified Evidence</strong>
                                    {!isEvidenceExpanded && <span className="text-[9px] text-slate-400 font-mono">({res.evidence.length} chars)</span>}
                                </div>
                                <div className="flex items-center gap-2">
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); handleReAnalyze(idx, res); }}
                                        className="px-2 py-1 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 rounded text-[9px] font-bold hover:bg-indigo-200 dark:hover:bg-indigo-800 transition-colors flex items-center gap-1 opacity-0 group-hover/evidence:opacity-100 focus:opacity-100"
                                        title="Re-run AI Analysis for ONLY this clause based on updated evidence"
                                    >
                                        <Icon name="RefreshCw" size={10}/> Re-evaluate
                                    </button>
                                </div>
                            </div>

                            {isEvidenceExpanded ? (
                                <textarea
                                    value={res.evidence}
                                    onChange={(e) => handleUpdateFinding(idx, 'evidence', e.target.value)}
                                    className="w-full bg-transparent outline-none text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-medium resize-y min-h-[150px] whitespace-pre-wrap font-mono custom-scrollbar border-l-2 border-transparent focus:border-indigo-400 pl-2 transition-all"
                                    placeholder="Evidence content..."
                                    spellCheck={false}
                                    disabled={isReanalyzing}
                                />
                            ) : (
                                <div 
                                    className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2 cursor-pointer font-mono opacity-80 hover:opacity-100"
                                    onClick={() => setExpandedEvidence(prev => ({...prev, [res.clauseId]: true}))}
                                >
                                    {res.evidence || "No evidence recorded."}
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="mb-2">
                        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-indigo-900/50 transition-colors group-focus-within:border-indigo-500 shadow-sm relative" onClick={e => e.stopPropagation()}>
                            <div className="flex justify-between items-center mb-1">
                                <strong className="text-[10px] font-bold text-purple-600 dark:text-purple-400 uppercase tracking-wider block">Auditor Conclusion ({notesLanguage.toUpperCase()})</strong>
                                {showTranslateBtn && (
                                    <button 
                                        onClick={() => handleTranslateReason(idx, res)}
                                        disabled={isTranslating}
                                        className="text-[9px] font-bold text-indigo-500 hover:text-indigo-700 flex items-center gap-1 bg-indigo-50 dark:bg-indigo-900/20 px-2 py-0.5 rounded transition-all active:scale-95"
                                    >
                                        {isTranslating ? <Icon name="Loader" className="animate-spin" size={10}/> : <Icon name="Globe" size={10}/>}
                                        Translate to {notesLanguage.toUpperCase()}
                                    </button>
                                )}
                            </div>

                            {isReanalyzing || isTranslating ? (
                                <div className="h-[60px] w-full bg-slate-50 dark:bg-slate-800 animate-pulse rounded"></div>
                            ) : (
                                <textarea
                                    value={displayReason}
                                    onChange={(e) => {
                                        // When editing, update the field corresponding to CURRENT view language
                                        const field = notesLanguage === 'vi' ? 'reason_vi' : 'reason_en';
                                        handleUpdateFinding(idx, field, e.target.value);
                                        // Also update main 'reason' if it's the first edit to keep sync or just keep them separate?
                                        if (notesLanguage === 'en') handleUpdateFinding(idx, 'reason', e.target.value);
                                    }}
                                    className="w-full bg-transparent outline-none text-base text-slate-800 dark:text-slate-200 leading-relaxed resize-none h-auto min-h-[60px]"
                                    placeholder={`Enter conclusion in ${notesLanguage === 'vi' ? 'Vietnamese' : 'English'}...`}
                                />
                            )}
                        </div>
                    </div>

                    {/* Shadow Review Result */}
                    {reviewText && (
                        <div className="mt-3 p-3 bg-purple-50 dark:bg-purple-900/20 border-l-4 border-purple-400 rounded-r-lg animate-in slide-in-from-top-2">
                            <div className="flex items-center gap-2 mb-1">
                                <Icon name="ShieldEye" size={12} className="text-purple-600"/>
                                <span className="text-[10px] font-bold text-purple-700 dark:text-purple-300 uppercase">AI Reviewer Note</span>
                            </div>
                            <p className="text-xs text-slate-600 dark:text-slate-300 italic leading-relaxed">"{reviewText}"</p>
                        </div>
                    )}

                    {res.suggestion && !reviewText && (
                        <div className="flex gap-2 items-start mt-3 opacity-80 group-hover:opacity-100 transition-opacity">
                            <div className="p-1 bg-amber-100 dark:bg-amber-900/30 rounded-full text-amber-600 dark:text-amber-400 shrink-0">
                                <Icon name="Lightbulb" size={10} />
                            </div>
                            <p className="text-[10px] text-slate-500 dark:text-slate-400 italic leading-tight pt-0.5">{res.suggestion}</p>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col gap-2 md:gap-4 animate-fade-in-up relative">
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1" ref={findingsContainerRef}>
                {!analysisResult && !isAnalyzeLoading && (
                    <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60">
                        <div className="p-6 bg-slate-100 dark:bg-slate-800 rounded-full mb-4 animate-pulse-slow">
                            <Icon name="Wand2" size={48} className="text-indigo-300 dark:text-indigo-600" />
                        </div>
                        <p className="font-bold">No analysis results yet.</p>
                        <p className="text-xs mt-2">Run analysis from the Audit tab to generate findings.</p>
                    </div>
                )}

                {/* --- NEURAL DASHBOARD OVERLAY (Matches ReportView Style) --- */}
                {isAnalyzeLoading && (
                    <div className="absolute inset-0 bg-white/95 dark:bg-slate-900/95 backdrop-blur-md z-50 flex flex-col items-center justify-center p-8 animate-in fade-in duration-300 rounded-3xl border border-white/20 dark:border-slate-800">
                        <div className="w-full max-w-lg space-y-6">
                            {/* Header */}
                            <div className="flex flex-col items-center">
                                <div className="relative w-16 h-16 mb-4">
                                    <div className="absolute inset-0 border-4 border-indigo-100 dark:border-slate-700 rounded-full"></div>
                                    <div className="absolute inset-0 border-t-4 border-indigo-600 rounded-full animate-spin"></div>
                                    <Icon name="Wand2" className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-500" size={24}/>
                                </div>
                                <h3 className="text-xl font-black text-slate-800 dark:text-white animate-pulse">{loadingMessage || "AI Auditor Analysis"}</h3>
                                <p className="text-sm text-slate-500 dark:text-slate-400 font-mono mt-1">{progressPercent}% Complete</p>
                            </div>

                            {/* Progress Bar */}
                            <div className="w-full h-2 bg-gray-200 dark:bg-slate-800 rounded-full overflow-hidden">
                                <div 
                                    className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-300 ease-out" 
                                    style={{ width: `${progressPercent}%` }}
                                ></div>
                            </div>

                            {/* Console Log */}
                            <div className="w-full h-40 bg-black/5 dark:bg-black/30 rounded-xl border border-gray-200 dark:border-slate-800 p-4 font-mono text-xs overflow-y-auto custom-scrollbar shadow-inner">
                                {analysisLogs.map((log, idx) => (
                                    <div key={idx} className="mb-1 text-slate-600 dark:text-slate-400 flex gap-2">
                                        <span className="text-indigo-400 select-none">&gt;</span>
                                        <span>{log}</span>
                                    </div>
                                ))}
                                {/* Anchor specifically for logs */}
                                <div ref={logsEndRef} />
                            </div>

                            {/* Context Indicator */}
                            {currentAnalyzingClause && (
                                <p className="text-xs text-center text-slate-400 font-mono mt-2 opacity-80 border-t border-slate-200 dark:border-slate-800 pt-2 w-full">
                                    Analyzing: {currentAnalyzingClause}
                                </p>
                            )}
                        </div>
                    </div>
                )}

                {analysisResult && (
                    viewMode === 'list' ? (
                        <div className="space-y-4 pb-10">
                            {analysisResult.map((res, idx) => renderFindingCard(res, idx))}
                        </div>
                    ) : (
                        <div className="flex flex-col h-full gap-4">
                            {/* Matrix Header Container - Collapsible */}
                            <div className={`flex-shrink-0 flex flex-col bg-white dark:bg-slate-900 rounded-2xl border ${themeConfig.borderClass.replace('border-', 'border-opacity-30 border-')} border-t-4 border-t-${themeConfig.borderClass.replace('border-', '')} dark:border-slate-800 overflow-hidden shadow-depth transition-all duration-300 ease-in-out ${isMatrixCollapsed ? 'h-11 min-h-[44px]' : 'h-auto max-h-[45vh]'}`}>

                                {/* Control Bar */}
                                <div className="flex items-center justify-between px-3 py-2 bg-white/50 dark:bg-slate-900/50 border-b border-gray-50 dark:border-slate-800 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800" onClick={() => setIsMatrixCollapsed(!isMatrixCollapsed)}>
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                                        <Icon name="Grid" size={12}/> Findings Matrix ({Object.keys(groupedFindings).length} Processes)
                                    </span>
                                    <div className="text-slate-400 hover:text-indigo-500 transition-colors">
                                        <Icon name={isMatrixCollapsed ? "ChevronDown" : "ChevronUp"} size={16} />
                                    </div>
                                </div>

                                {/* Matrix Content - Only rendered fully when not collapsed to save DOM/Layout calc, or hidden via CSS for animation */}
                                <div className={`flex flex-col transition-opacity duration-200 ${isMatrixCollapsed ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
                                    {/* UPDATED GRID: [Clause] | [Major] | [Minor] | [OFI] | [Comp] */}
                                    <div className={`grid grid-cols-[80px_1fr_1fr_1fr_1fr] gap-1 p-3 border-b border-gray-100 dark:border-slate-800 ${themeConfig.bgSoft} sticky top-0 z-10 transition-colors duration-500 ease-fluid`}>
                                        <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Clause</div>
                                        <div className="text-[10px] font-bold text-red-500 uppercase tracking-widest text-center">Major</div>
                                        <div className="text-[10px] font-bold text-orange-500 uppercase tracking-widest text-center">Minor</div>
                                        <div className="text-[10px] font-bold text-blue-500 uppercase tracking-widest text-center">OFI</div>
                                        <div className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest text-center">Comp</div>
                                    </div>
                                    <div className="overflow-y-auto custom-scrollbar max-h-[40vh] p-2">
                                        {Object.entries(groupedFindings).map(([processName, items]) => {
                                            const isCollapsed = collapsedGroups.has(processName);
                                            const typedItems = items as { finding: AnalysisResult, originalIndex: number }[];
                                            const countNC = typedItems.filter(i => i.finding.status === 'NC_MAJOR' || i.finding.status === 'NC_MINOR').length;

                                            return (
                                                <div key={processName} className="flex flex-col mb-2 rounded-xl border border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/50 overflow-hidden">
                                                    {/* Group Header */}
                                                    <div 
                                                        className="flex items-center justify-between px-3 py-2 bg-white dark:bg-slate-900 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800 transition-colors"
                                                        onClick={() => toggleGroup(processName)}
                                                    >
                                                        <div className="flex items-center gap-2">
                                                            <Icon name="ChevronDown" size={14} className={`text-slate-400 transition-transform duration-300 ${isCollapsed ? '-rotate-90' : ''}`}/>
                                                            <span className="text-xs font-bold text-indigo-600 dark:text-indigo-300 uppercase tracking-wide truncate max-w-[200px]" title={processName}>
                                                                {processName} 
                                                            </span>
                                                            <span className="text-[10px] text-slate-400 font-normal">({typedItems.length})</span>
                                                        </div>
                                                        {countNC > 0 && <span className="text-[9px] font-bold text-red-500 bg-red-50 dark:bg-red-900/20 px-2 py-0.5 rounded shadow-sm">{countNC} NCs</span>}
                                                    </div>

                                                    {/* Group Items with SCROLLABLE CONTAINER */}
                                                    {!isCollapsed && (
                                                        <div className="max-h-[240px] overflow-y-auto custom-scrollbar divide-y divide-gray-100 dark:divide-slate-800/50 border-t border-gray-100 dark:border-slate-800">
                                                            {typedItems.map(({ finding: item, originalIndex: idx }) => {
                                                                const isSelected = focusedFindingIndex === idx;
                                                                return (
                                                                    <div key={idx} onClick={() => setFocusedFindingIndex(idx)} className={`grid grid-cols-[80px_1fr_1fr_1fr_1fr] gap-1 py-2 cursor-pointer transition-colors ${isSelected ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'hover:bg-slate-100 dark:hover:bg-slate-800/80'}`}>
                                                                        <div className={`flex items-center justify-center h-full w-full text-[10px] font-mono font-bold ${isSelected ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400'}`}>{item.clauseId}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'NC_MAJOR' && <div className="w-4 h-4 rounded bg-red-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Major NC"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'NC_MINOR' && <div className="w-4 h-4 rounded bg-orange-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Minor NC"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'OFI' && <div className="w-4 h-4 rounded bg-blue-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Opportunity for Improvement"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'COMPLIANT' && <div className="w-4 h-4 rounded bg-emerald-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Compliant"></div>}</div>
                                                                    </div>
                                                                );
                                                            })}
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>

                            {/* Detail Panel */}
                            <div className="flex-1 min-h-0 overflow-y-auto custom-scrollbar bg-slate-50/50 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800 p-2 shadow-inner">
                                {analysisResult[focusedFindingIndex] ? renderFindingCard(analysisResult[focusedFindingIndex], focusedFindingIndex, true) : <div className="h-full flex items-center justify-center text-slate-400 italic text-xs">Select a row above to view details</div>}
                            </div>
                        </div>
                    )
                )}
            </div>
            {/* Toolbar kept same as before */}
            <div className="flex-shrink-0 flex flex-row items-center md:justify-end gap-2 md:gap-3 w-full pt-2">
                <div className="flex-1 md:flex-none md:w-auto h-[52px] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl p-1 flex items-center shadow-sm min-w-0 dark:shadow-md">
                    <button onClick={() => setViewMode('list')} className={`flex-1 md:flex-none md:w-auto h-full px-4 rounded-lg flex items-center justify-center gap-2 transition-all whitespace-nowrap ${viewMode === 'list' ? 'bg-indigo-500 text-white shadow-md' : 'text-slate-400 hover:text-slate-600 hover:bg-gray-50 dark:hover:bg-slate-800'}`} title="List View"><Icon name="LayoutList" size={18} /><span className="hidden md:inline text-xs font-bold">List</span></button>
                    <button onClick={() => setViewMode('matrix')} className={`flex-1 md:flex-none md:w-auto h-full px-4 rounded-lg flex items-center justify-center gap-2 transition-all whitespace-nowrap ${viewMode === 'matrix' ? 'bg-indigo-500 text-white shadow-md' : 'text-slate-400 hover:text-slate-600 hover:bg-gray-50 dark:hover:bg-slate-800'}`} title="Matrix View"><Icon name="Grid" size={18} /><span className="hidden md:inline text-xs font-bold">Matrix</span></button>
                </div>

                {analysisResult && (
                    <button 
                        onClick={handleToggleSelectAll}
                        className={`flex-none md:w-auto px-4 h-[52px] border rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm whitespace-nowrap dark:shadow-md ${isAllSelected ? 'bg-indigo-50 border-indigo-200 text-indigo-600 dark:bg-indigo-900/20 dark:border-indigo-800 dark:text-indigo-400' : 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:bg-gray-50'}`}
                    >
                        <Icon name={isAllSelected ? "CheckSquare" : "Square"} size={18}/>
                        <span className="hidden lg:inline">{isAllSelected ? "Deselect All" : "Select All"}</span>
                    </button>
                )}

                <button onClick={() => onExport('notes', notesLanguage)} disabled={!analysisResult} className="flex-none md:w-auto px-6 h-[52px] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 whitespace-nowrap dark:shadow-md hover:shadow-lg">
                    <Icon name="Download" />
                    <span className="hidden md:inline">Export Findings</span>
                    <div className="lang-pill-container">
                        <span onClick={(e) => { e.stopPropagation(); setNotesLanguage('en'); }} className={`lang-pill-btn ${notesLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setNotesLanguage('vi'); }} className={`lang-pill-btn ${notesLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { Icon } from '../UI';
import { AnalysisResult, FindingStatus, FindingsViewMode } from '../../types';
import { TABS_CONFIG } from '../../constants';
import { performShadowReview, generateAnalysis, translateChunk } from '../../services/geminiService';
import { useKeyPool } from '../../contexts/KeyPoolContext';
import { useUI } from '../../contexts/UIContext';
import { useAudit } from '../../contexts/AuditContext';

interface FindingsViewProps {
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    isAnalyzeLoading: boolean;
    loadingMessage: string;
    currentAnalyzingClause: string;
    viewMode: FindingsViewMode;
    setViewMode: (mode: FindingsViewMode) => void;
    focusedFindingIndex: number;
    setFocusedFindingIndex: (index: number) => void;
    onExport: (type: 'notes', lang: 'en' | 'vi') => void;
    notesLanguage: 'en' | 'vi';
    setNotesLanguage: (lang: 'en' | 'vi') => void;
    progressPercent?: number; // Added
    analysisLogs?: string[]; // Added
}

export const FindingsView: React.FC<FindingsViewProps> = ({
    analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings,
    isAnalyzeLoading, loadingMessage, currentAnalyzingClause,
    viewMode, setViewMode, focusedFindingIndex, setFocusedFindingIndex,
    onExport, notesLanguage, setNotesLanguage, progressPercent = 0, analysisLogs = []
}) => {
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);
    const logsEndRef = useRef<HTMLDivElement>(null);

    // Contexts
    const { getActiveKey } = useKeyPool();
    const { showToast } = useUI();
    const { standards, standardKey, privacySettings } = useAudit();

    // Local state for Shadow Review
    const [reviewLoading, setReviewLoading] = useState<string | null>(null); // Clause ID
    const [reviews, setReviews] = useState<Record<string, string>>({});

    // Local state for Re-Analysis (Single Clause)
    const [reanalyzingId, setReanalyzingId] = useState<string | null>(null);
    const [translatingId, setTranslatingId] = useState<string | null>(null);

    // Grouping State
    const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

    // UI State for Evidence Expansion
    const [expandedEvidence, setExpandedEvidence] = useState<Record<string, boolean>>({});

    // Matrix Visibility State
    const [isMatrixCollapsed, setIsMatrixCollapsed] = useState(false);

    const themeConfig = TABS_CONFIG.find(t => t.id === 'findings')!;

    useEffect(() => {
        if (viewMode === 'list' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult?.length, viewMode]);

    // Auto-scroll logs
    useEffect(() => {
        if (isAnalyzeLoading && logsEndRef.current) {
            logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [analysisLogs, isAnalyzeLoading]);

    // Computed: Are all visible items selected?
    const isAllSelected = useMemo(() => {
        if (!analysisResult || analysisResult.length === 0) return false;
        return analysisResult.every(res => selectedFindings[res.clauseId]);
    }, [analysisResult, selectedFindings]);

    // Computed: Group Findings by Process
    const groupedFindings = useMemo((): Record<string, { finding: AnalysisResult, originalIndex: number }[]> => {
        if (!analysisResult) return {};
        const groups: Record<string, { finding: AnalysisResult, originalIndex: number }[]> = {};

        analysisResult.forEach((finding, index) => {
            const processName = finding.processName || "General Audit";
            if (!groups[processName]) {
                groups[processName] = [];
            }
            groups[processName].push({ finding, originalIndex: index });
        });

        // Sort keys to ensure consistent order
        return Object.keys(groups).sort().reduce((acc, key) => {
            acc[key] = groups[key];
            return acc;
        }, {} as typeof groups);
    }, [analysisResult]);

    const toggleGroup = (groupName: string) => {
        setCollapsedGroups(prev => {
            const next = new Set(prev);
            if (next.has(groupName)) next.delete(groupName);
            else next.add(groupName);
            return next;
        });
    };

    const handleToggleSelectAll = () => {
        if (!analysisResult) return;
        const newSelection: Record<string, boolean> = {};
        const targetState = !isAllSelected;

        analysisResult.forEach(res => {
            newSelection[res.clauseId] = targetState;
        });

        setSelectedFindings(prev => ({ ...prev, ...newSelection }));
        showToast(targetState ? "All Findings Selected" : "All Findings Deselected");
    };

    const handleUpdateFinding = (index: number, field: keyof AnalysisResult, value: string) => {
        setAnalysisResult(prev => {
            if (!prev) return null;
            const newArr = [...prev];
            newArr[index] = { ...newArr[index], [field]: value };
            return newArr;
        });
        // Auto-scroll only on status change, not text editing
        if (field === 'status' && analysisResult) {
            const nextIndex = index + 1;
            if (nextIndex < analysisResult.length && findingRefs.current[nextIndex]) {
                setTimeout(() => findingRefs.current[nextIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' }), 100);
            }
        }
    };

    const handleShadowReview = async (e: React.MouseEvent, finding: AnalysisResult) => {
        e.stopPropagation();
        const keyProfile = getActiveKey();
        if (!keyProfile) return showToast("API Key Required for Review");

        setReviewLoading(finding.clauseId);
        try {
            const critique = await performShadowReview(finding, keyProfile.key, keyProfile.activeModel);
            setReviews(prev => ({ ...prev, [finding.clauseId]: critique }));
        } catch (err) {
            showToast("Review Failed");
        } finally {
            setReviewLoading(null);
        }
    };

    // --- RE-EVALUATION LOGIC ---
    const handleReAnalyze = async (index: number, finding: AnalysisResult) => {
        const keyProfile = getActiveKey();
        if (!keyProfile) return showToast("API Key Required");
        if (!standardKey || !standards[standardKey]) return showToast("Standard context missing");

        setReanalyzingId(finding.clauseId);

        try {
            // 1. Find Clause Data
            const currentStd = standards[standardKey];
            const findClauseData = (id: string) => {
                const traverse = (list: any[]): any => {
                    for (const c of list) {
                        if (c.id === id || c.code === id) return c;
                        if (c.subClauses) {
                            const found = traverse(c.subClauses);
                            if (found) return found;
                        }
                    }
                    return null;
                };
                for (const g of currentStd.groups) {
                    const found = traverse(g.clauses);
                    if (found) return found;
                }
                return null;
            };

            const clauseData = findClauseData(finding.clauseId);
            if (!clauseData) throw new Error("Clause definition not found");

            // 2. Call AI with Updated Evidence
            const resultJson = await generateAnalysis(
                { code: clauseData.code, title: clauseData.title, description: clauseData.description },
                currentStd.name,
                finding.evidence, // Use the potentially EDITED evidence
                "", // No tags context needed for re-eval, user input is truth
                keyProfile.key,
                keyProfile.activeModel,
                privacySettings.maskCompany
            );

            const parsed = JSON.parse(resultJson);

            // 3. Update State (Merge Result)
            setAnalysisResult(prev => {
                if (!prev) return null;
                const newArr = [...prev];
                // Keep the edited evidence, update status/reason/suggestion
                newArr[index] = { 
                    ...newArr[index], 
                    status: parsed.status,
                    reason: parsed.reason,
                    reason_en: parsed.reason_en,
                    reason_vi: parsed.reason_vi,
                    suggestion: parsed.suggestion,
                    conclusion_report: parsed.conclusion_report
                };
                return newArr;
            });
            showToast("Finding Re-evaluated Successfully");

        } catch (error: any) {
            console.error(error);
            showToast("Re-evaluation Failed: " + error.message);
        } finally {
            setReanalyzingId(null);
        }
    };

    // --- INSTANT TRANSLATION LOGIC ---
    const handleTranslateReason = async (index: number, finding: AnalysisResult) => {
        const keyProfile = getActiveKey();
        if (!keyProfile) return showToast("API Key Required");

        setTranslatingId(finding.clauseId);
        try {
            const targetLang = notesLanguage;
            const textToTranslate = finding.reason || "";
            if(!textToTranslate) return;

            const translated = await translateChunk(textToTranslate, targetLang, keyProfile.key);

            setAnalysisResult(prev => {
                if (!prev) return null;
                const newArr = [...prev];
                // Save to the appropriate field
                if(targetLang === 'vi') newArr[index] = { ...newArr[index], reason_vi: translated };
                else newArr[index] = { ...newArr[index], reason_en: translated };
                return newArr;
            });
            showToast("Translation complete.");
        } catch(e) {
            showToast("Translation failed.");
        } finally {
            setTranslatingId(null);
        }
    };

    const getFindingColorStyles = (status: FindingStatus) => {
        switch (status) {
            case 'COMPLIANT': return { bg: 'bg-emerald-500', text: 'text-emerald-700 dark:text-emerald-300', pill: 'bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300', border: 'border-emerald-500' };
            case 'NC_MAJOR': return { bg: 'bg-red-600', text: 'text-red-700 dark:text-red-300', pill: 'bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-300', border: 'border-red-600' };
            case 'NC_MINOR': return { bg: 'bg-orange-500', text: 'text-orange-700 dark:text-orange-300', pill: 'bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-400', border: 'border-orange-500' };
            case 'OFI': return { bg: 'bg-blue-500', text: 'text-blue-700 dark:text-blue-300', pill: 'bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300', border: 'border-blue-500' };
            default: return { bg: 'bg-slate-500', text: 'text-slate-600', pill: 'bg-slate-100 text-slate-500', border: 'border-slate-300' };
        }
    };

    const renderFindingCard = (res: AnalysisResult, idx: number, isCondensed = false) => {
        const styles = getFindingColorStyles(res.status as FindingStatus);
        const reviewText = reviews[res.clauseId];
        const isReviewing = reviewLoading === res.clauseId;
        const isReanalyzing = reanalyzingId === res.clauseId;
        const isTranslating = translatingId === res.clauseId;
        const isEvidenceExpanded = expandedEvidence[res.clauseId] || false;

        // Determine displayed reason text based on language preference
        let displayReason = res.reason;
        const hasVi = !!res.reason_vi;
        const hasEn = !!res.reason_en;

        if (notesLanguage === 'vi') {
            displayReason = res.reason_vi || res.reason; 
        } else {
            displayReason = res.reason_en || res.reason;
        }

        // Check if we need to offer translation (e.g. user wants VI but we only have default/EN)
        const showTranslateBtn = (notesLanguage === 'vi' && !hasVi) || (notesLanguage === 'en' && !hasEn && !res.reason.match(/^[A-Za-z]/)); 

        return (
            <div
                key={idx}
                ref={!isCondensed ? el => { findingRefs.current[idx] = el; } : null}
                className={`group relative bg-white dark:bg-slate-900 rounded-2xl p-4 md:p-5 border-l-[6px] transition-all duration-300 hover:shadow-depth-lg dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05)] ${styles.border} ${selectedFindings[res.clauseId] ? 'ring-2 ring-indigo-500/20 translate-x-2' : 'hover:translate-x-1 opacity-95 hover:opacity-100'} animate-in slide-in-from-bottom-2 fade-in fill-mode-backwards`}
                style={{ animationDelay: `${idx * 50}ms` }}
                onClick={() => setSelectedFindings(prev => ({ ...prev, [res.clauseId]: !prev[res.clauseId] }))}
            >
                {/* Header Controls */}
                <div className="absolute top-4 right-4 z-10 flex gap-2">
                    <button 
                        onClick={(e) => handleShadowReview(e, res)}
                        disabled={isReviewing}
                        className={`p-1.5 rounded-full transition-all border ${reviewText ? 'bg-purple-100 text-purple-600 border-purple-200' : 'bg-gray-100 text-slate-400 hover:text-purple-600 hover:bg-purple-50 border-transparent'}`}
                        title="AI Shadow Review (Critique Finding)"
                    >
                        {isReviewing ? <Icon name="Loader" className="animate-spin" size={14}/> : <Icon name="ShieldEye" size={14}/>}
                    </button>
                    {selectedFindings[res.clauseId] ? (
                        <div className="bg-emerald-100 dark:bg-emerald-900/30 rounded-full p-1 text-emerald-600 dark:text-emerald-400">
                            <Icon name="CheckThick" size={18} />
                        </div>
                    ) : (
                        <div className="w-6 h-6 rounded-full border-2 border-gray-200 dark:border-slate-700 group-hover:border-indigo-400 transition-colors"></div>
                    )}
                </div>

                <div className="pr-12">
                    <div className="flex items-center gap-3 mb-4 flex-wrap">
                        <span className="text-xs font-black text-slate-500 dark:text-slate-400 bg-gray-100 dark:bg-slate-800 px-2 py-1 rounded-lg border border-gray-200 dark:border-slate-700">{res.clauseId}</span>
                        {res.processName && (
                            <span className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded border border-indigo-100 dark:border-indigo-800 flex items-center gap-1">
                                <Icon name="Session11_GridAdd" size={10} /> {res.processName}
                            </span>
                        )}
                        <div className="relative group/badge" onClick={e => e.stopPropagation()}>
                            <select
                                value={res.status}
                                onChange={(e) => handleUpdateFinding(idx, 'status', e.target.value)}
                                className={`appearance-none cursor-pointer text-[10px] font-black uppercase tracking-wider px-3 py-1 rounded-full ${styles.pill} border-none outline-none hover:brightness-95 text-center transition-all shadow-sm`}
                            >
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="COMPLIANT">COMPLIANT</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="NC_MINOR">MINOR NC</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="NC_MAJOR">MAJOR NC</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="OFI">OFI</option>
                            </select>
                        </div>
                    </div>

                    {/* COLLAPSIBLE EVIDENCE SECTION */}
                    <div className="mb-4 group/evidence relative">
                        {isReanalyzing && (
                            <div className="absolute inset-0 z-20 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm rounded-xl flex items-center justify-center border border-indigo-100 dark:border-indigo-900">
                                <div className="flex flex-col items-center">
                                    <Icon name="Loader" className="animate-spin text-indigo-500 mb-2" size={24}/>
                                    <span className="text-xs font-bold text-indigo-600 dark:text-indigo-400 animate-pulse">Re-evaluating based on updates...</span>
                                </div>
                            </div>
                        )}

                        <div className="bg-slate-50 dark:bg-slate-950/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800 relative transition-colors focus-within:border-indigo-300 dark:focus-within:border-indigo-700 focus-within:ring-1 focus-within:ring-indigo-500/20" onClick={e => e.stopPropagation()}>
                            <div className="flex justify-between items-center mb-2">
                                <div 
                                    className="flex items-center gap-2 cursor-pointer select-none" 
                                    onClick={() => setExpandedEvidence(prev => ({...prev, [res.clauseId]: !prev[res.clauseId]}))}
                                >
                                    <Icon name={isEvidenceExpanded ? "ChevronDown" : "ChevronRight"} size={12} className="text-indigo-500"/>
                                    <strong className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider block">Verified Evidence</strong>
                                    {!isEvidenceExpanded && <span className="text-[9px] text-slate-400 font-mono">({res.evidence.length} chars)</span>}
                                </div>
                                <div className="flex items-center gap-2">
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); handleReAnalyze(idx, res); }}
                                        className="px-2 py-1 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 rounded text-[9px] font-bold hover:bg-indigo-200 dark:hover:bg-indigo-800 transition-colors flex items-center gap-1 opacity-0 group-hover/evidence:opacity-100 focus:opacity-100"
                                        title="Re-run AI Analysis for ONLY this clause based on updated evidence"
                                    >
                                        <Icon name="RefreshCw" size={10}/> Re-evaluate
                                    </button>
                                </div>
                            </div>

                            {isEvidenceExpanded ? (
                                <textarea
                                    value={res.evidence}
                                    onChange={(e) => handleUpdateFinding(idx, 'evidence', e.target.value)}
                                    className="w-full bg-transparent outline-none text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-medium resize-y min-h-[150px] whitespace-pre-wrap font-mono custom-scrollbar border-l-2 border-transparent focus:border-indigo-400 pl-2 transition-all"
                                    placeholder="Evidence content..."
                                    spellCheck={false}
                                    disabled={isReanalyzing}
                                />
                            ) : (
                                <div 
                                    className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2 cursor-pointer font-mono opacity-80 hover:opacity-100"
                                    onClick={() => setExpandedEvidence(prev => ({...prev, [res.clauseId]: true}))}
                                >
                                    {res.evidence || "No evidence recorded."}
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="mb-2">
                        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-indigo-900/50 transition-colors group-focus-within:border-indigo-500 shadow-sm relative" onClick={e => e.stopPropagation()}>
                            <div className="flex justify-between items-center mb-1">
                                <strong className="text-[10px] font-bold text-purple-600 dark:text-purple-400 uppercase tracking-wider block">Auditor Conclusion ({notesLanguage.toUpperCase()})</strong>
                                {showTranslateBtn && (
                                    <button 
                                        onClick={() => handleTranslateReason(idx, res)}
                                        disabled={isTranslating}
                                        className="text-[9px] font-bold text-indigo-500 hover:text-indigo-700 flex items-center gap-1 bg-indigo-50 dark:bg-indigo-900/20 px-2 py-0.5 rounded transition-all active:scale-95"
                                    >
                                        {isTranslating ? <Icon name="Loader" className="animate-spin" size={10}/> : <Icon name="Globe" size={10}/>}
                                        Translate to {notesLanguage.toUpperCase()}
                                    </button>
                                )}
                            </div>

                            {isReanalyzing || isTranslating ? (
                                <div className="h-[60px] w-full bg-slate-50 dark:bg-slate-800 animate-pulse rounded"></div>
                            ) : (
                                <textarea
                                    value={displayReason}
                                    onChange={(e) => {
                                        // When editing, update the field corresponding to CURRENT view language
                                        const field = notesLanguage === 'vi' ? 'reason_vi' : 'reason_en';
                                        handleUpdateFinding(idx, field, e.target.value);
                                        // Also update main 'reason' if it's the first edit to keep sync or just keep them separate?
                                        if (notesLanguage === 'en') handleUpdateFinding(idx, 'reason', e.target.value);
                                    }}
                                    className="w-full bg-transparent outline-none text-base text-slate-800 dark:text-slate-200 leading-relaxed resize-none h-auto min-h-[60px]"
                                    placeholder={`Enter conclusion in ${notesLanguage === 'vi' ? 'Vietnamese' : 'English'}...`}
                                />
                            )}
                        </div>
                    </div>

                    {/* Shadow Review Result */}
                    {reviewText && (
                        <div className="mt-3 p-3 bg-purple-50 dark:bg-purple-900/20 border-l-4 border-purple-400 rounded-r-lg animate-in slide-in-from-top-2">
                            <div className="flex items-center gap-2 mb-1">
                                <Icon name="ShieldEye" size={12} className="text-purple-600"/>
                                <span className="text-[10px] font-bold text-purple-700 dark:text-purple-300 uppercase">AI Reviewer Note</span>
                            </div>
                            <p className="text-xs text-slate-600 dark:text-slate-300 italic leading-relaxed">"{reviewText}"</p>
                        </div>
                    )}

                    {res.suggestion && !reviewText && (
                        <div className="flex gap-2 items-start mt-3 opacity-80 group-hover:opacity-100 transition-opacity">
                            <div className="p-1 bg-amber-100 dark:bg-amber-900/30 rounded-full text-amber-600 dark:text-amber-400 shrink-0">
                                <Icon name="Lightbulb" size={10} />
                            </div>
                            <p className="text-[10px] text-slate-500 dark:text-slate-400 italic leading-tight pt-0.5">{res.suggestion}</p>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col gap-2 md:gap-4 animate-fade-in-up relative">
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1" ref={findingsContainerRef}>
                {!analysisResult && !isAnalyzeLoading && (
                    <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60">
                        <div className="p-6 bg-slate-100 dark:bg-slate-800 rounded-full mb-4 animate-pulse-slow">
                            <Icon name="Wand2" size={48} className="text-indigo-300 dark:text-indigo-600" />
                        </div>
                        <p className="font-bold">No analysis results yet.</p>
                        <p className="text-xs mt-2">Run analysis from the Audit tab to generate findings.</p>
                    </div>
                )}

                {/* --- NEURAL DASHBOARD OVERLAY (Matches ReportView Style) --- */}
                {isAnalyzeLoading && (
                    <div className="absolute inset-0 bg-white/95 dark:bg-slate-900/95 backdrop-blur-md z-50 flex flex-col items-center justify-center p-8 animate-in fade-in duration-300 rounded-3xl border border-white/20 dark:border-slate-800">
                        <div className="w-full max-w-lg space-y-6">
                            {/* Header */}
                            <div className="flex flex-col items-center">
                                <div className="relative w-16 h-16 mb-4">
                                    <div className="absolute inset-0 border-4 border-indigo-100 dark:border-slate-700 rounded-full"></div>
                                    <div className="absolute inset-0 border-t-4 border-indigo-600 rounded-full animate-spin"></div>
                                    <Icon name="Wand2" className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-500" size={24}/>
                                </div>
                                <h3 className="text-xl font-black text-slate-800 dark:text-white animate-pulse">{loadingMessage || "AI Auditor Analysis"}</h3>
                                <p className="text-sm text-slate-500 dark:text-slate-400 font-mono mt-1">{progressPercent}% Complete</p>
                            </div>

                            {/* Progress Bar */}
                            <div className="w-full h-2 bg-gray-200 dark:bg-slate-800 rounded-full overflow-hidden">
                                <div 
                                    className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-300 ease-out" 
                                    style={{ width: `${progressPercent}%` }}
                                ></div>
                            </div>

                            {/* Console Log */}
                            <div className="w-full h-40 bg-black/5 dark:bg-black/30 rounded-xl border border-gray-200 dark:border-slate-800 p-4 font-mono text-xs overflow-y-auto custom-scrollbar shadow-inner">
                                {analysisLogs.map((log, idx) => (
                                    <div key={idx} className="mb-1 text-slate-600 dark:text-slate-400 flex gap-2">
                                        <span className="text-indigo-400 select-none">&gt;</span>
                                        <span>{log}</span>
                                    </div>
                                ))}
                                {/* Anchor specifically for logs */}
                                <div ref={logsEndRef} />
                            </div>

                            {/* Context Indicator */}
                            {currentAnalyzingClause && (
                                <p className="text-xs text-center text-slate-400 font-mono mt-2 opacity-80 border-t border-slate-200 dark:border-slate-800 pt-2 w-full">
                                    Analyzing: {currentAnalyzingClause}
                                </p>
                            )}
                        </div>
                    </div>
                )}

                {analysisResult && (
                    viewMode === 'list' ? (
                        <div className="space-y-4 pb-10">
                            {analysisResult.map((res, idx) => renderFindingCard(res, idx))}
                        </div>
                    ) : (
                        <div className="flex flex-col h-full gap-4">
                            {/* Matrix Header Container - Collapsible */}
                            <div className={`flex-shrink-0 flex flex-col bg-white dark:bg-slate-900 rounded-2xl border ${themeConfig.borderClass.replace('border-', 'border-opacity-30 border-')} border-t-4 border-t-${themeConfig.borderClass.replace('border-', '')} dark:border-slate-800 overflow-hidden shadow-depth transition-all duration-300 ease-in-out ${isMatrixCollapsed ? 'h-11 min-h-[44px]' : 'h-auto max-h-[45vh]'}`}>

                                {/* Control Bar */}
                                <div className="flex items-center justify-between px-3 py-2 bg-white/50 dark:bg-slate-900/50 border-b border-gray-50 dark:border-slate-800 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800" onClick={() => setIsMatrixCollapsed(!isMatrixCollapsed)}>
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                                        <Icon name="Grid" size={12}/> Findings Matrix ({Object.keys(groupedFindings).length} Processes)
                                    </span>
                                    <div className="text-slate-400 hover:text-indigo-500 transition-colors">
                                        <Icon name={isMatrixCollapsed ? "ChevronDown" : "ChevronUp"} size={16} />
                                    </div>
                                </div>

                                {/* Matrix Content - Only rendered fully when not collapsed to save DOM/Layout calc, or hidden via CSS for animation */}
                                <div className={`flex flex-col transition-opacity duration-200 ${isMatrixCollapsed ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
                                    {/* UPDATED GRID: [Clause] | [Major] | [Minor] | [OFI] | [Comp] */}
                                    <div className={`grid grid-cols-[80px_1fr_1fr_1fr_1fr] gap-1 p-3 border-b border-gray-100 dark:border-slate-800 ${themeConfig.bgSoft} sticky top-0 z-10 transition-colors duration-500 ease-fluid`}>
                                        <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Clause</div>
                                        <div className="text-[10px] font-bold text-red-500 uppercase tracking-widest text-center">Major</div>
                                        <div className="text-[10px] font-bold text-orange-500 uppercase tracking-widest text-center">Minor</div>
                                        <div className="text-[10px] font-bold text-blue-500 uppercase tracking-widest text-center">OFI</div>
                                        <div className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest text-center">Comp</div>
                                    </div>
                                    <div className="overflow-y-auto custom-scrollbar max-h-[40vh] p-2">
                                        {Object.entries(groupedFindings).map(([processName, items]) => {
                                            const isCollapsed = collapsedGroups.has(processName);
                                            const typedItems = items as { finding: AnalysisResult, originalIndex: number }[];
                                            const countNC = typedItems.filter(i => i.finding.status === 'NC_MAJOR' || i.finding.status === 'NC_MINOR').length;

                                            return (
                                                <div key={processName} className="flex flex-col mb-2 rounded-xl border border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/50 overflow-hidden">
                                                    {/* Group Header */}
                                                    <div 
                                                        className="flex items-center justify-between px-3 py-2 bg-white dark:bg-slate-900 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800 transition-colors"
                                                        onClick={() => toggleGroup(processName)}
                                                    >
                                                        <div className="flex items-center gap-2">
                                                            <Icon name="ChevronDown" size={14} className={`text-slate-400 transition-transform duration-300 ${isCollapsed ? '-rotate-90' : ''}`}/>
                                                            <span className="text-xs font-bold text-indigo-600 dark:text-indigo-300 uppercase tracking-wide truncate max-w-[200px]" title={processName}>
                                                                {processName} 
                                                            </span>
                                                            <span className="text-[10px] text-slate-400 font-normal">({typedItems.length})</span>
                                                        </div>
                                                        {countNC > 0 && <span className="text-[9px] font-bold text-red-500 bg-red-50 dark:bg-red-900/20 px-2 py-0.5 rounded shadow-sm">{countNC} NCs</span>}
                                                    </div>

                                                    {/* Group Items with AUTO HEIGHT (No inner scroll) */}
                                                    {!isCollapsed && (
                                                        <div className="divide-y divide-gray-100 dark:divide-slate-800/50 border-t border-gray-100 dark:border-slate-800">
                                                            {typedItems.map(({ finding: item, originalIndex: idx }) => {
                                                                const isSelected = focusedFindingIndex === idx;
                                                                return (
                                                                    <div key={idx} onClick={() => setFocusedFindingIndex(idx)} className={`grid grid-cols-[80px_1fr_1fr_1fr_1fr] gap-1 py-2 cursor-pointer transition-colors ${isSelected ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'hover:bg-slate-100 dark:hover:bg-slate-800/80'}`}>
                                                                        <div className={`flex items-center justify-center h-full w-full text-[10px] font-mono font-bold ${isSelected ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400'}`}>{item.clauseId}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'NC_MAJOR' && <div className="w-4 h-4 rounded bg-red-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Major NC"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'NC_MINOR' && <div className="w-4 h-4 rounded bg-orange-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Minor NC"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'OFI' && <div className="w-4 h-4 rounded bg-blue-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Opportunity for Improvement"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'COMPLIANT' && <div className="w-4 h-4 rounded bg-emerald-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Compliant"></div>}</div>
                                                                    </div>
                                                                );
                                                            })}
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>

                            {/* Detail Panel */}
                            <div className="flex-1 min-h-0 overflow-y-auto custom-scrollbar bg-slate-50/50 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800 p-2 shadow-inner">
                                {analysisResult[focusedFindingIndex] ? renderFindingCard(analysisResult[focusedFindingIndex], focusedFindingIndex, true) : <div className="h-full flex items-center justify-center text-slate-400 italic text-xs">Select a row above to view details</div>}
                            </div>
                        </div>
                    )
                )}
            </div>
            {/* Toolbar kept same as before */}
            <div className="flex-shrink-0 flex flex-row items-center md:justify-end gap-2 md:gap-3 w-full pt-2">
                <div className="flex-1 md:flex-none md:w-auto h-[52px] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-xl p-1 flex items-center shadow-sm min-w-0 dark:shadow-md">
                    <button onClick={() => setViewMode('list')} className={`flex-1 md:flex-none md:w-auto h-full px-4 rounded-lg flex items-center justify-center gap-2 transition-all whitespace-nowrap ${viewMode === 'list' ? 'bg-indigo-500 text-white shadow-md' : 'text-slate-400 hover:text-slate-600 hover:bg-gray-50 dark:hover:bg-slate-800'}`} title="List View"><Icon name="LayoutList" size={18} /><span className="hidden md:inline text-xs font-bold">List</span></button>
                    <button onClick={() => setViewMode('matrix')} className={`flex-1 md:flex-none md:w-auto h-full px-4 rounded-lg flex items-center justify-center gap-2 transition-all whitespace-nowrap ${viewMode === 'matrix' ? 'bg-indigo-500 text-white shadow-md' : 'text-slate-400 hover:text-slate-600 hover:bg-gray-50 dark:hover:bg-slate-800'}`} title="Matrix View"><Icon name="Grid" size={18} /><span className="hidden md:inline text-xs font-bold">Matrix</span></button>
                </div>

                {analysisResult && (
                    <button 
                        onClick={handleToggleSelectAll}
                        className={`flex-none md:w-auto px-4 h-[52px] border rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm whitespace-nowrap dark:shadow-md ${isAllSelected ? 'bg-indigo-50 border-indigo-200 text-indigo-600 dark:bg-indigo-900/20 dark:border-indigo-800 dark:text-indigo-400' : 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:bg-gray-50'}`}
                    >
                        <Icon name={isAllSelected ? "CheckSquare" : "Square"} size={18}/>
                        <span className="hidden lg:inline">{isAllSelected ? "Deselect All" : "Select All"}</span>
                    </button>
                )}

                <button onClick={() => onExport('notes', notesLanguage)} disabled={!analysisResult} className="flex-none md:w-auto px-6 h-[52px] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 whitespace-nowrap dark:shadow-md hover:shadow-lg">
                    <Icon name="Download" />
                    <span className="hidden md:inline">Export Findings</span>
                    <div className="lang-pill-container">
                        <span onClick={(e) => { e.stopPropagation(); setNotesLanguage('en'); }} className={`lang-pill-btn ${notesLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setNotesLanguage('vi'); }} className={`lang-pill-btn ${notesLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { Icon } from '../UI';
import { Standard, Clause } from '../../types';
import { copyToClipboard } from '../../utils';

interface StandardExplorerProps {
    standard: Standard | undefined;
    standardKey: string;
    selectedClauses: string[]; // Kept for highlighting active context if needed, but not modification
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>; // Kept for API compat, but unused for toggling
    onReferenceClause: (clause: Clause) => void;
    repairedIds: string[];
    onScrollTrigger?: () => void;
}

export const StandardExplorer: React.FC<StandardExplorerProps> = ({
    standard, standardKey, onReferenceClause, repairedIds, onScrollTrigger
}) => {
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);
    const [copiedClauseId, setCopiedClauseId] = useState<string | null>(null);

    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    // Helper to restore distinctive colors for groups
    const getGroupStyle = (id: string) => {
        const key = id.toUpperCase();
        if (key.includes('PLAN')) return 'bg-orange-50 hover:bg-orange-100 dark:bg-orange-900/20 dark:hover:bg-orange-900/30 text-orange-700 dark:text-orange-400';
        if (key.includes('SUPPORT')) return 'bg-blue-50 hover:bg-blue-100 dark:bg-blue-900/20 dark:hover:bg-blue-900/30 text-blue-700 dark:text-blue-400';
        if (key.includes('DO')) return 'bg-cyan-50 hover:bg-cyan-100 dark:bg-cyan-900/20 dark:hover:bg-cyan-900/30 text-cyan-700 dark:text-cyan-400';
        if (key.includes('CHECK') || key.includes('ACT')) return 'bg-emerald-50 hover:bg-emerald-100 dark:bg-emerald-900/20 dark:hover:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400';
        if (key.includes('ANNEX')) return 'bg-purple-50 hover:bg-purple-100 dark:bg-purple-900/20 dark:hover:bg-purple-900/30 text-purple-700 dark:text-purple-400';
        return 'bg-gray-50 hover:bg-gray-100 dark:bg-slate-800/30 dark:hover:bg-slate-800 text-slate-700 dark:text-slate-300';
    };

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id);
        const isCopied = copiedClauseId === c.id;
        const isRepaired = repairedIds.includes(c.id);

        return (
            <div key={c.id} className={`flex flex-col transition-all duration-300 ${level > 0 ? 'ml-3 pl-3 border-l dark:border-slate-800' : ''}`}>
                <div 
                    className={`group flex items-start gap-2 p-1.5 rounded-lg transition-all duration-200 ease-soft cursor-pointer ${isRepaired ? 'bg-emerald-50/80 dark:bg-emerald-900/20 ring-1 ring-emerald-500/30' : 'hover:bg-gray-100/80 dark:hover:bg-slate-800/50'}`}
                    onClick={() => hasSubs && toggleClauseExpand(c.id)}
                >
                    <div className="flex-1 min-w-0">
                        <div className="flex items-start justify-between gap-1.5">
                            <div className="flex items-start gap-2">
                                <span className={`text-[10px] font-black uppercase shrink-0 px-1.5 py-0.5 rounded border mt-0.5 ${level === 0 ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-700' : 'bg-transparent border-transparent text-slate-400'}`}>
                                    {c.code}
                                </span>
                                <span className={`text-xs font-medium tracking-tight leading-snug break-words pt-0.5 ${level === 0 ? 'text-slate-800 dark:text-slate-200' : 'text-slate-600 dark:text-slate-400'}`}>
                                    {c.title}
                                </span>
                                {isRepaired && <span className="text-[8px] font-black bg-emerald-100 text-emerald-600 px-1 py-0.5 rounded animate-pulse shrink-0">FIX</span>}
                            </div>

                            {/* Hover Actions */}
                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity shrink-0">
                                <button onClick={(e) => { e.stopPropagation(); onReferenceClause(c); }} className="p-1 text-slate-400 hover:text-indigo-500 dark:hover:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded" title="Read Content">
                                    <Icon name="BookOpen" size={12} />
                                </button>
                                <button
                                    onClick={(e) => handleSingleClauseCopy(e, c)}
                                    className={`p-1 ${isCopied ? 'text-emerald-500' : 'text-slate-400 hover:text-indigo-500'} hover:bg-gray-100 dark:hover:bg-slate-800 rounded`}
                                    title="Copy Title"
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={12} />
                                </button>
                                {hasSubs && <Icon name="ChevronDown" size={10} className={`text-slate-300 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}/>}
                            </div>
                        </div>
                        {level === 0 && (
                            <div className="text-[10px] text-slate-400 dark:text-slate-500 italic mt-0.5 line-clamp-2 pl-1">
                                {c.description}
                            </div>
                        )}
                    </div>
                </div>

                {/* Accordion Body */}
                {hasSubs && isExpanded && (
                    <div className="mt-0.5 flex flex-col animate-accordion-down overflow-hidden">
                        {c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-white dark:bg-slate-950 w-full md:min-w-[390px]">
            <div className="p-3 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/50 sticky top-0 z-10 backdrop-blur-sm">
                <div className="flex items-center justify-between">
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                        <Icon name="Book" size={12}/> Reference Explorer
                    </span>
                    <span className="text-[9px] text-slate-300 bg-slate-100 dark:bg-slate-800 dark:text-slate-600 px-1.5 py-0.5 rounded">
                        Read-Only
                    </span>
                </div>
            </div>

            <div 
                className="flex-1 overflow-y-auto custom-scrollbar p-3 scroll-smooth"
                onScroll={(e) => {
                    if (e.currentTarget.scrollTop > 30 && onScrollTrigger) onScrollTrigger();
                }}
            >
                <div className="flex flex-col gap-3 pb-12">
                    {!standard ? (
                        <div className="text-center text-slate-400 mt-20 italic text-xs uppercase tracking-widest opacity-50">Select a Standard</div>
                    ) : (
                        standard.groups.map(g => {
                            const isGroupExpanded = expandedGroups.includes(g.id);
                            const groupColorStyle = getGroupStyle(g.id);

                            return (
                                <div key={g.id} className="bg-white dark:bg-slate-900 rounded-xl border border-gray-100 dark:border-slate-800 overflow-hidden transition-all duration-300">
                                    <div 
                                        className={`flex items-center justify-between p-3 cursor-pointer transition-colors select-none ${groupColorStyle}`} 
                                        onClick={() => toggleGroupExpand(g.id)}
                                    >
                                        <div className="flex items-center gap-2.5">
                                            <div className="p-1.5 rounded-lg bg-white/60 dark:bg-black/20 shadow-sm">
                                                <Icon name={g.icon} size={14}/>
                                            </div>
                                            <h4 className="text-xs font-black uppercase tracking-wider opacity-90">{g.title}</h4>
                                        </div>
                                        <Icon name="ChevronDown" size={12} className={`transition-transform duration-300 opacity-60 ${isGroupExpanded ? 'rotate-180' : ''}`}/>
                                    </div>

                                    {isGroupExpanded && (
                                        <div className="p-2 space-y-1 bg-white dark:bg-slate-900 border-t border-gray-100 dark:border-slate-800 animate-accordion-down">
                                             {g.clauses.map(c => renderClauseItem(c))}
                                        </div>
                                    )}
                                </div>
                            );
                        })
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Icon, Modal } from './UI';
import { Clause } from '../types';
import { copyToClipboard } from '../utils';

interface ReferenceClauseModalProps {
    isOpen: boolean;
    onClose: () => void;
    clause: Clause | null;
    standardName: string;
    fullText: { en: string; vi: string };
    isLoading: boolean;
}

const ReferenceClauseModal = ({ isOpen, onClose, clause, standardName, fullText, isLoading }: ReferenceClauseModalProps) => {
    const [lang, setLang] = useState<'en' | 'vi'>('en');
    const [isCopied, setIsCopied] = useState(false);
    const [streamedText, setStreamedText] = useState("");

    const textToDisplay = lang === 'en' ? fullText.en : fullText.vi;

    // Logic to derive badge style similar to App.tsx
    const badgeData = useMemo(() => {
        if (!standardName) return { text: "ISO", colorClass: "bg-gray-100 text-gray-600" };

        const match = standardName.match(/\((.*?)\)/);
        const shortName = match ? match[1] : (standardName.split(' ')[0] || 'ISO');
        const textUpper = shortName.toUpperCase();

        let colorClass = "bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 border-indigo-100 dark:border-indigo-800/50";
        if (textUpper.includes('EMS') || textUpper.includes('14001')) colorClass = "bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-700/50";
        else if (textUpper.includes('QMS') || textUpper.includes('9001')) colorClass = "bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 border-blue-200 dark:border-blue-700/50";
        else if (textUpper.includes('ISMS') || textUpper.includes('27001')) colorClass = "bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300 border-purple-200 dark:border-purple-700/50";

        return { text: shortName, colorClass };
    }, [standardName]);

    useEffect(() => {
        if (!isOpen) { 
            setStreamedText("");
            return;
        }

        if (isLoading || !textToDisplay) {
            setStreamedText(""); 
            return;
        }

        // Split by explicit newline for cleaner streaming effect
        const lines = textToDisplay.split('\n');
        let currentIndex = 0;
        let currentText = "";

        const startTimeout = setTimeout(() => {
            const interval = setInterval(() => {
                if (currentIndex < lines.length) {
                    // Re-append the newline that was removed by split
                    currentText += (lines[currentIndex] || '') + '\n';
                    setStreamedText(currentText);
                    currentIndex++;
                } else {
                    clearInterval(interval);
                }
            }, 20); // Faster streaming for better UX

            return () => clearInterval(interval);
        }, 50);

        return () => clearTimeout(startTimeout);
    }, [isOpen, textToDisplay, isLoading]);

    const handleCopy = () => {
        copyToClipboard(textToDisplay);
        setIsCopied(true);
        setTimeout(() => setIsCopied(false), 2000);
    };

    return (
        <Modal isOpen={isOpen} title="Clause Reference" onClose={onClose}>
            <div className="flex flex-col h-full gap-3">
                {/* Header: Title & Code */}
                {clause && (
                    <div className="flex items-start gap-3 pb-2 border-b border-gray-100 dark:border-slate-800">
                         <span className="text-sm font-black text-indigo-700 dark:text-indigo-400 uppercase bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded-lg border border-indigo-100 dark:border-indigo-800 shrink-0">{clause.code}</span>
                         <h4 className="text-sm font-bold text-slate-800 dark:text-white leading-tight mt-1">{clause.title}</h4>
                    </div>
                )}

                {isLoading ? (
                    <div className="h-64 flex flex-col items-center justify-center text-slate-500 gap-4">
                        <div className="relative w-16 h-16">
                            <div className="absolute inset-0 border-2 border-indigo-200 dark:border-indigo-800 rounded-full opacity-20"></div>
                            <div className="absolute inset-0 border-t-2 border-indigo-600 rounded-full animate-spin"></div>
                        </div>
                        <span className="text-sm font-bold animate-pulse">Consulting Gemini AI Auditor...</span>
                    </div>
                ) : (
                    <>
                        {/* Compact Toolbar: Badge | Language | Actions */}
                        <div className="flex flex-wrap items-center justify-between gap-2">
                            <div className="flex items-center gap-2">
                                {/* Standard Badge */}
                                <span className={`text-[10px] font-bold px-2 py-1 rounded-full border shadow-sm uppercase tracking-wider ${badgeData.colorClass}`}>
                                    {badgeData.text}
                                </span>

                                {/* Compact Language Toggle */}
                                <div className="lang-pill-container shadow-sm border-gray-200 dark:border-slate-700">
                                    <span onClick={() => setLang('en')} className={`lang-pill-btn ${lang === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                                    <span onClick={() => setLang('vi')} className={`lang-pill-btn ${lang === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 ml-auto">
                                <button 
                                    onClick={handleCopy} 
                                    disabled={isCopied}
                                    className={`p-2 rounded-xl transition-all hover:scale-110 active:scale-95 disabled:opacity-70 border shadow-sm ${isCopied ? 'text-emerald-600 border-emerald-200 bg-emerald-50 dark:bg-emerald-900/20' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:text-indigo-600'}`}
                                    title={isCopied ? "Copied!" : "Copy to Clipboard"}
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={16}/>
                                </button>
                            </div>
                        </div>

                        {/* Content Area */}
                        <div className="flex-1 p-4 overflow-y-auto custom-scrollbar bg-gray-50/50 dark:bg-slate-950/50 rounded-2xl border border-gray-100 dark:border-slate-800 relative shadow-inner text-left">
                            <div className="prose prose-sm dark:prose-invert max-w-none">
                                <p className="text-xs md:text-sm text-slate-800 dark:text-slate-200 whitespace-pre-wrap leading-7 font-medium tracking-wide">
                                    {streamedText}
                                    {!isLoading && streamedText !== textToDisplay && (
                                        <span className="inline-block w-1.5 h-4 bg-indigo-500 animate-pulse ml-1 align-middle"></span>
                                    )}
                                </p>
                            </div>
                        </div>
                    </>
                )}
            </div>
        </Modal>
    );
};

export default ReferenceClauseModal;

import React, { useState, useEffect, useMemo, Suspense } from 'react';
import { AuditProvider, useAudit } from './contexts/AuditContext';
import { UIProvider, useUI } from './contexts/UIContext';
import { KeyPoolProvider, useKeyPool } from './contexts/KeyPoolContext';
import { MainLayout } from './components/layout/MainLayout';
import { TabNavigation } from './components/TabNavigation';
// Lazy Load Views
import { AINeuralLoader } from './components/ui/Loaders';
import ReferenceClauseModal from './components/ReferenceClauseModal';
import { SettingsModal } from './components/modals/SettingsModal';
import { AddStandardModal } from './components/modals/AddStandardModal';
import { ExportProgressModal } from './components/modals/ExportProgressModal';
import { Icon } from './components/UI';
import { TABS_CONFIG } from './constants';
import { useAutoSave } from './hooks/useAutoSave';
import { UploadedFile, FindingsViewMode, MatrixRow } from './types'; 
import { processSourceFile } from './utils';

// New Custom Hooks
import { useAuditWorkflow } from './hooks/useAuditWorkflow';
import { useReportGenerator } from './hooks/useReportGenerator';
import { useExportManager } from './hooks/useExportManager';
import { useKeyboardNavigation } from './hooks/useKeyboardNavigation';

// Lazy Components
const EvidenceView = React.lazy(() => import('./components/views/EvidenceView').then(module => ({ default: module.EvidenceView })));
const FindingsView = React.lazy(() => import('./components/views/FindingsView').then(module => ({ default: module.FindingsView })));
const ReportView = React.lazy(() => import('./components/views/ReportView').then(module => ({ default: module.ReportView })));
const PlanningView = React.lazy(() => import('./components/views/PlanningView').then(module => ({ default: module.PlanningView })));

const AppContent = () => {
    const [layoutMode, setLayoutMode] = useState('planning'); 

    // Enable Global Keyboard Navigation (Arrow Keys)
    useKeyboardNavigation();

    // Contexts
    const { isSidebarOpen, sidebarWidth, showToast, modals, toggleModal, setSidebarOpen } = useUI();
    const { 
        evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
        selectedClauses, standards, standardKey, auditInfo,
        setKnowledgeData, analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings,
        finalReportText, setFinalReportText, resetSession, restoreSession,
        addCustomStandard, setStandardKey, activeProcessId, processes, privacySettings
    } = useAudit();

    const { apiKeys, addKey, deleteKey, refreshKeyStatus, activeKeyId, isCheckingKey, isAutoCheckEnabled, toggleAutoCheck } = useKeyPool();
    const { lastSavedTime, isSaving, createManualBackup } = useAutoSave();

    // Local UI State
    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);
    const [referenceState, setReferenceState] = useState({ isOpen: false, clause: null, fullText: {en:"", vi:""}, isLoading: false });
    const [newKeyInput, setNewKeyInput] = useState(""); 

    // View Persistence
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');
    const [focusedFindingIndex, setFocusedFindingIndex] = useState(0);
    const [evidenceLanguage, setEvidenceLanguage] = useState<'en' | 'vi'>('en');
    const [notesLanguage, setNotesLanguage] = useState<'en' | 'vi'>('en');
    const [exportLanguage, setExportLanguage] = useState<'en' | 'vi'>('en');

    // --- INTEGRATE HOOKS ---
    const { 
        handleAnalyze, isAnalyzeLoading, currentAnalyzingClause, 
        progressPercent, analysisLogs 
    } = useAuditWorkflow();

    const { 
        isReportLoading, reportLoadingMessage, reportTemplateName, isTemplateProcessing,
        handleTemplateUpload, handleGenerateReport, generationLogs, progressPercent: reportProgress
    } = useReportGenerator(exportLanguage);
    const { 
        handleExport, exportState, setExportState, 
        rescueKey, setRescueKey, handleResumeExport, isRescuing, handleSkipExportChunk 
    } = useExportManager();

    // Event Listeners
    useEffect(() => {
        const handleRef = (e: CustomEvent) => setReferenceState({ isOpen: true, clause: e.detail, fullText: {en:"", vi:""}, isLoading: true });
        const handleRefUpdate = (e: CustomEvent) => setReferenceState(prev => ({ ...prev, fullText: e.detail, isLoading: false }));
        const handleSwitch = (e: CustomEvent) => { if (e.detail) setLayoutMode(e.detail); };

        window.addEventListener('OPEN_REFERENCE', handleRef as any);
        window.addEventListener('UPDATE_REFERENCE_CONTENT', handleRefUpdate as any);
        window.addEventListener('SWITCH_LAYOUT', handleSwitch as any);
        return () => {
            window.removeEventListener('OPEN_REFERENCE', handleRef as any);
            window.removeEventListener('UPDATE_REFERENCE_CONTENT', handleRefUpdate as any);
            window.removeEventListener('SWITCH_LAYOUT', handleSwitch as any);
        };
    }, []);

    // Helper: Dynamic Styles
    const liquidColorClass = useMemo(() => {
        const config = TABS_CONFIG.find(t => t.id === layoutMode);
        return config ? `${config.colorClass} ${config.borderClass}` : 'bg-slate-500 border-slate-600';
    }, [layoutMode]);

    const themeStyles = useMemo(() => {
        switch (layoutMode) {
            case 'planning': return 'selection:bg-orange-200 selection:text-orange-900 dark:selection:bg-orange-900 dark:selection:text-orange-100 bg-orange-50/80 dark:bg-orange-950/20';
            case 'evidence': return 'selection:bg-blue-200 selection:text-blue-900 dark:selection:bg-blue-900 dark:selection:text-blue-100 bg-blue-50/80 dark:bg-blue-950/20';
            case 'findings': return 'selection:bg-purple-200 selection:text-purple-900 dark:selection:bg-purple-900 dark:selection:text-purple-100 bg-purple-50/80 dark:bg-purple-950/20';
            case 'report': return 'selection:bg-emerald-200 selection:text-emerald-900 dark:selection:bg-emerald-900 dark:selection:text-emerald-100 bg-emerald-50/80 dark:bg-emerald-950/20';
            default: return 'selection:bg-indigo-200 selection:text-indigo-900';
        }
    }, [layoutMode]);

    const currentTabConfig = TABS_CONFIG.find(t => t.id === layoutMode) || TABS_CONFIG[0];
    const showProcessBlocker = (!activeProcessId || processes.length === 0) && layoutMode !== 'planning';

    const handleAddKeyWrapper = async () => {
        const status = await addKey(newKeyInput);
        if (status === 'valid') { setNewKeyInput(""); showToast("Success: API Key is Active"); } 
        else if (status === 'quota_exceeded') { setNewKeyInput(""); showToast("Added: Key Quota Exhausted"); } 
        else if (status === 'duplicate') showToast("Info: Key already exists"); 
        else showToast("Failed: Invalid API Key or Network Error");
    };

    const isReadyForAnalysis = useMemo(() => {
        if (!standardKey || !activeProcessId || isAnalyzeLoading) return false;
        // Explicitly type the iterator to MatrixRow[] to avoid 'unknown' error
        const hasMatrixData = Object.values(matrixData).some((rows: MatrixRow[]) => rows.some(r => r.status === 'supplied'));
        const hasGlobalEvidence = evidence && evidence.trim().length > 10;
        return hasMatrixData || hasGlobalEvidence;
    }, [standardKey, activeProcessId, matrixData, evidence, isAnalyzeLoading]);

    // Wrap Analyze with Auto-Switch
    const handleAnalyzeClick = async () => {
        setLayoutMode('findings'); // Auto-switch to see progress
        await handleAnalyze();
    };

    return (
        <MainLayout commandActions={[]} onRestoreSnapshot={restoreSession}>
            {/* Top Bar - Color Synced Border Top */}
            <div className={`flex-shrink-0 px-4 md:px-6 py-3 border-b border-gray-200 dark:border-slate-800 transition-colors duration-500 ease-fluid flex justify-between items-center gap-3 border-t-4 ${currentTabConfig.borderClass} ${liquidColorClass.split(' ')[0].replace('bg-', 'bg-opacity-10 ')}`}>
                <div className="flex-1 min-w-0">
                    <TabNavigation 
                        layoutMode={layoutMode} 
                        setLayoutMode={setLayoutMode}
                        isSidebarOpen={isSidebarOpen}
                        sidebarWidth={sidebarWidth}
                    />
                </div>
                <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                    <button onClick={() => toggleModal('recall', true)} className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all border shadow-sm ${lastSavedTime ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600' : 'bg-white dark:bg-slate-800 text-slate-500'}`}>
                        <div className="relative">
                            <Icon name="History" size={18}/>
                            {lastSavedTime && <span className="absolute -top-1 -right-1 flex h-2.5 w-2.5"><span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${isSaving ? 'bg-red-500' : 'bg-emerald-500'}`}></span></span>}
                        </div>
                        <span className="hidden xl:inline text-xs font-bold">Recall</span>
                    </button>
                    <button onClick={() => { if(confirm("Start New Session?")) { createManualBackup(); resetSession(); showToast("Session Reset."); }}} className="h-10 px-4 bg-amber-50 dark:bg-amber-950/30 text-amber-600 border border-amber-200 rounded-xl flex items-center justify-center gap-2 hover:bg-amber-100 transition-all shadow-sm">
                        <Icon name="Session4_FilePlus" size={18}/>
                        <span className="hidden md:inline text-xs font-bold">New</span>
                    </button>
                </div>
            </div>

            {/* MAIN CONTENT WRAPPER */}
            <div className={`flex-1 overflow-hidden relative p-2 md:p-4 transition-colors duration-500 ease-fluid ${themeStyles}`}>
                {showProcessBlocker && (
                    <div className="absolute inset-0 z-50 bg-white/80 dark:bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center animate-in fade-in">
                        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-floating border border-indigo-100 dark:border-indigo-900 max-w-md text-center">
                            <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/50 rounded-full flex items-center justify-center mx-auto mb-4 text-indigo-600"><Icon name="Session11_GridAdd" size={32} /></div>
                            <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">Process Required</h3>
                            <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 leading-relaxed">Define at least one <strong>Process</strong> to begin evidence collection.</p>
                            <div className="flex gap-3 justify-center">
                                <button onClick={() => setLayoutMode('planning')} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg transition-transform active:scale-95">Go to Planning</button>
                            </div>
                        </div>
                    </div>
                )}

                <Suspense fallback={<AINeuralLoader message="Loading View..." />}>
                    {layoutMode === 'planning' && <PlanningView />}

                    {layoutMode === 'evidence' && (
                        <EvidenceView
                            key={activeProcessId} // Forces a fresh mount when switching processes to prevent state bleeding
                            evidence={evidence} setEvidence={setEvidence}
                            uploadedFiles={uploadedFiles} setUploadedFiles={setUploadedFiles}
                            onOcrProcess={() => {}} isOcrLoading={false}
                            onAnalyze={handleAnalyzeClick} 
                            isReadyForAnalysis={isReadyForAnalysis} 
                            isAnalyzeLoading={isAnalyzeLoading} 
                            analyzeTooltip="Run AI Analysis"
                            onExport={handleExport} 
                            evidenceLanguage={evidenceLanguage} setEvidenceLanguage={setEvidenceLanguage}
                            textareaRef={{ current: null }} tags={evidenceTags} onAddTag={addEvidenceTag}
                            selectedClauses={selectedClauses} standards={standards} standardKey={standardKey}
                            matrixData={matrixData} setMatrixData={setMatrixData}
                        />
                    )}

                    {layoutMode === 'findings' && (
                        <FindingsView
                            analysisResult={analysisResult} setAnalysisResult={setAnalysisResult}
                            selectedFindings={selectedFindings} setSelectedFindings={setSelectedFindings}
                            isAnalyzeLoading={isAnalyzeLoading} loadingMessage="Scanning Matrix Evidence..." 
                            currentAnalyzingClause={currentAnalyzingClause}
                            viewMode={findingsViewMode} setViewMode={setFindingsViewMode}
                            focusedFindingIndex={focusedFindingIndex} setFocusedFindingIndex={setFocusedFindingIndex}
                            onExport={handleExport} 
                            notesLanguage={notesLanguage} setNotesLanguage={setNotesLanguage}
                            progressPercent={progressPercent}
                            analysisLogs={analysisLogs}
                        />
                    )}

                    {layoutMode === 'report' && (
                        <ReportView
                            finalReportText={finalReportText} setFinalReportText={setFinalReportText}
                            isReportLoading={isReportLoading} loadingMessage={reportLoadingMessage}
                            templateFileName={reportTemplateName}
                            isTemplateProcessing={isTemplateProcessing}
                            handleTemplateUpload={handleTemplateUpload} 
                            handleGenerateReport={handleGenerateReport}
                            isReadyToSynthesize={!!analysisResult && analysisResult.length > 0} 
                            onExport={handleExport} 
                            exportLanguage={exportLanguage} setExportLanguage={setExportLanguage}
                            analysisResult={analysisResult} // Pass results for Stage Builder
                            generationLogs={generationLogs}
                            progressPercent={reportProgress}
                            selectedFindings={selectedFindings} // PASS SELECTION STATE
                        />
                    )}
                </Suspense>
            </div>

            {/* Modals */}
            <SettingsModal 
                isOpen={modals.settings} onClose={() => toggleModal('settings', false)} 
                apiKeys={apiKeys} newKeyInput={newKeyInput} setNewKeyInput={setNewKeyInput} 
                isCheckingKey={isCheckingKey} handleAddKey={handleAddKeyWrapper}
                activeKeyId={activeKeyId} editingKeyId={null} editLabelInput="" setEditLabelInput={() => {}}
                handleSaveLabel={() => {}} handleStartEdit={() => {}} handleRefreshStatus={refreshKeyStatus} handleDeleteKey={deleteKey}
                isAutoCheckEnabled={isAutoCheckEnabled} toggleAutoCheck={toggleAutoCheck}
            />

            <AddStandardModal
                isOpen={modals.addStandard} onClose={() => toggleModal('addStandard', false)}
                onAdd={async (name, file) => {
                    toggleModal('addStandard', false);
                    const newKey = `CUSTOM_${Date.now()}`;
                    if(file) { const text = await processSourceFile(file); setKnowledgeData(text, file.name); }
                    addCustomStandard(newKey, { name, description: "Custom", groups: [] });
                    setStandardKey(newKey);
                }}
            />

            <ReferenceClauseModal
                isOpen={referenceState.isOpen} onClose={() => setReferenceState(prev => ({...prev, isOpen: false}))}
                clause={referenceState.clause} standardName={standards[standardKey]?.name || ""}
                fullText={referenceState.fullText} isLoading={referenceState.isLoading}
            />

            <ExportProgressModal 
                exportState={exportState} setExportState={setExportState}
                rescueKey={rescueKey} setRescueKey={setRescueKey}
                handleResumeExport={handleResumeExport} isRescuing={isRescuing}
                onClose={() => setExportState(prev => ({ ...prev, isOpen: false }))}
                onSkip={handleSkipExportChunk}
            />
        </MainLayout>
    );
};

export default function App() {
    return (
        <UIProvider>
            <KeyPoolProvider>
                <AuditProvider>
                    <AppContent />
                </AuditProvider>
            </KeyPoolProvider>
        </UIProvider>
    );
}

import React, { useState, useMemo, useRef, memo, useCallback } from 'react';
import { Icon } from '../UI';
import { useAudit } from '../../contexts/AuditContext';
import { Clause } from '../../types';
import { useUI } from '../../contexts/UIContext';
import { cleanFileName } from '../../utils';
import { TABS_CONFIG } from '../../constants';

// --- INTERNAL TYPES ---
interface PlanningRowProps {
    clause: Clause;
    level: number;
    processes: any[];
    onSmartToggle: (procId: string, clause: Clause) => void; 
}

// --- HELPER: Get all descendant IDs ---
const getFlatClauseIds = (clause: Clause): string[] => {
    let ids = [clause.id];
    if (clause.subClauses) {
        clause.subClauses.forEach(sub => {
            ids = [...ids, ...getFlatClauseIds(sub)];
        });
    }
    return ids;
};

// --- MEMOIZED ROW COMPONENT ---
const PlanningRow = memo(({ 
    clause, level, processes, onSmartToggle 
}: PlanningRowProps) => {

    const selfAndDescendants = useMemo(() => getFlatClauseIds(clause), [clause]);
    const isParent = clause.subClauses && clause.subClauses.length > 0;

    return (
        <tr className="hover:bg-gray-50 dark:hover:bg-slate-800/30 transition-colors group duration-300 ease-fluid">
            <td className="p-2 border-r border-gray-100 dark:border-slate-800 sticky left-0 bg-white dark:bg-slate-900 group-hover:bg-gray-50 dark:group-hover:bg-slate-800/30 z-10 align-top transition-colors duration-300 ease-fluid">
                <div className={`flex flex-col gap-1 ${level > 0 ? 'ml-4 border-l-2 border-gray-200 dark:border-slate-800 pl-2' : ''}`}>
                    <div className="flex items-center gap-2">
                        <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold whitespace-nowrap ${level === 0 ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-700' : 'text-slate-400'}`}>
                            {clause.code}
                        </span>
                        <span className={`text-xs truncate ${level === 0 ? 'font-bold text-slate-800 dark:text-slate-200' : 'font-medium text-slate-600 dark:text-slate-400'}`}>
                            {clause.title}
                        </span>
                    </div>
                </div>
            </td>
            {processes.map(p => {
                let status: 'all' | 'some' | 'none' = 'none';

                if (isParent) {
                    const activeCount = selfAndDescendants.reduce((acc, id) => acc + (p.matrixData[id] ? 1 : 0), 0);
                    if (activeCount === selfAndDescendants.length) status = 'all';
                    else if (activeCount > 0) status = 'some';
                } else {
                    status = p.matrixData[clause.id] ? 'all' : 'none';
                }

                return (
                    <td key={`${p.id}_${clause.id}`} className="p-1 text-center border-r border-gray-50 dark:border-slate-800/50 last:border-0 relative align-middle">
                        <div className="flex justify-center">
                            <button
                                onClick={() => onSmartToggle(p.id, clause)}
                                className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all duration-300 ease-spring ${
                                    status === 'all' 
                                        ? 'bg-emerald-500 text-white shadow-sm shadow-emerald-500/40 transform scale-105' 
                                        : status === 'some'
                                            ? 'bg-orange-100 dark:bg-orange-900/30 text-orange-500 border border-orange-200 dark:border-orange-800'
                                            : 'bg-slate-50 dark:bg-slate-800/50 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-300'
                                }`}
                                title={status === 'all' ? "Fully Planned" : status === 'some' ? "Partially Planned (Click to Fill)" : "Click to Plan"}
                            >
                                {status === 'all' && (isParent ? <Icon name="CheckCircle2" size={14}/> : <Icon name="CheckThick" size={14}/>)}
                                {status === 'some' && <div className="w-2.5 h-2.5 rounded-full bg-orange-500"></div>}
                            </button>
                        </div>
                    </td>
                );
            })}
        </tr>
    );
}, (prev, next) => {
    if (prev.processes.length !== next.processes.length) return false;

    const hasChange = prev.processes.some((pp, idx) => {
        const np = next.processes[idx];
        return pp.matrixData !== np.matrixData;
    });

    return !hasChange; 
});


export const PlanningView = () => {
    const { 
        standards, standardKey, processes, 
        addProcess, batchUpdateProcessClauses, toggleProcessClause
    } = useAudit();

    const { showToast, setSidebarOpen } = useUI();
    const [search, setSearch] = useState("");
    const [exportLang, setExportLang] = useState<'en' | 'vi'>('en');
    const fileInputRef = useRef<HTMLInputElement>(null);
    const searchInputRef = useRef<HTMLInputElement>(null);

    const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

    const currentStandard = standards[standardKey];

    // --- COLOR THEME SYNC ---
    const themeConfig = TABS_CONFIG.find(t => t.id === 'planning')!;

    const getPDCAStyle = (groupId: string) => {
        const key = groupId.toUpperCase();
        if (key.includes('PLAN')) return 'bg-orange-50 hover:bg-orange-100 dark:bg-orange-900/20 dark:hover:bg-orange-900/30 text-orange-700 dark:text-orange-400 border-l-4 border-orange-500';
        if (key.includes('SUPPORT')) return 'bg-blue-50 hover:bg-blue-100 dark:bg-blue-900/20 dark:hover:bg-blue-900/30 text-blue-700 dark:text-blue-400 border-l-4 border-blue-500';
        if (key.includes('DO')) return 'bg-cyan-50 hover:bg-cyan-100 dark:bg-cyan-900/20 dark:hover:bg-cyan-900/30 text-cyan-700 dark:text-cyan-400 border-l-4 border-cyan-500';
        if (key.includes('CHECK') || key.includes('ACT')) return 'bg-emerald-50 hover:bg-emerald-100 dark:bg-emerald-900/20 dark:hover:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 border-l-4 border-emerald-500';
        if (key.includes('ANNEX')) return 'bg-purple-50 hover:bg-purple-100 dark:bg-purple-900/20 dark:hover:bg-purple-900/30 text-purple-700 dark:text-purple-400 border-l-4 border-purple-500';
        return `${themeConfig.bgSoft} border-l-4 ${themeConfig.borderClass} ${themeConfig.textClass}`;
    };

    const getGroupClauses = useMemo(() => (clauses: Clause[]) => {
        const flat: { clause: Clause, level: number }[] = [];
        const traverse = (list: Clause[], level: number) => {
            list.forEach(c => {
                flat.push({ clause: c, level });
                if(c.subClauses) traverse(c.subClauses, level + 1);
            });
        };
        traverse(clauses, 0);
        return flat;
    }, []); 

    const handleSmartToggle = useCallback((processId: string, clause: Clause) => {
        const proc = processes.find(p => p.id === processId);
        if (!proc) return;

        const allIds = getFlatClauseIds(clause);
        const isGroup = allIds.length > 1;

        if (!isGroup) {
            toggleProcessClause(processId, clause.id);
        } else {
            const activeCount = allIds.reduce((acc, id) => acc + (proc.matrixData[id] ? 1 : 0), 0);
            const isFullyActive = activeCount === allIds.length;

            if (isFullyActive) {
                allIds.forEach(id => {
                    if (proc.matrixData[id]) toggleProcessClause(processId, id);
                });
            } else {
                const toAdd = allIds.filter(id => !proc.matrixData[id]);
                if (toAdd.length > 0) {
                    batchUpdateProcessClauses([{ processId, clauses: toAdd }]);
                }
            }
        }
    }, [processes, toggleProcessClause, batchUpdateProcessClauses]);

    const handleGroupToggle = (e: React.MouseEvent, processId: string, clausesInGroup: Clause[]) => {
        e.stopPropagation();
        const flatIds: string[] = [];
        const traverse = (list: Clause[]) => list.forEach(c => {
            flatIds.push(c.id);
            if(c.subClauses) traverse(c.subClauses);
        });
        traverse(clausesInGroup);

        const proc = processes.find(p => p.id === processId);
        if (!proc) return;

        const allSelected = flatIds.every(cid => !!proc.matrixData[cid]);

        if (allSelected) {
            flatIds.forEach(cid => {
                if (proc.matrixData[cid]) toggleProcessClause(processId, cid);
            });
        } else {
            const toAdd = flatIds.filter(cid => !proc.matrixData[cid]);
            batchUpdateProcessClauses([{ processId, clauses: toAdd }]);
        }
    };

    const toggleGroupCollapse = (groupId: string) => {
        setCollapsedGroups(prev => {
            const next = new Set(prev);
            if (next.has(groupId)) next.delete(groupId);
            else next.add(groupId);
            return next;
        });
    };

    const areAllCollapsed = useMemo(() => {
        if (!currentStandard) return false;
        return currentStandard.groups.every(g => collapsedGroups.has(g.id));
    }, [currentStandard, collapsedGroups]);

    const handleToggleAll = () => {
        if (!currentStandard) return;
        const allGroupIds = currentStandard.groups.map(g => g.id);

        if (areAllCollapsed) {
            setCollapsedGroups(new Set());
        } else {
            setCollapsedGroups(new Set(allGroupIds));
        }
    };

    const coverageStats = useMemo(() => {
        if (!currentStandard) return { percent: 0, covered: 0, total: 0 };
        let total = 0;
        const traverse = (list: Clause[]) => list.forEach(c => { total++; if(c.subClauses) traverse(c.subClauses); });
        currentStandard.groups.forEach(g => traverse(g.clauses));

        if (total === 0) return { percent: 0, covered: 0, total: 0 };

        const coveredSet = new Set<string>();
        processes.forEach(p => {
            Object.keys(p.matrixData).forEach(cid => coveredSet.add(cid));
        });

        return {
            percent: Math.round((coveredSet.size / total) * 100),
            covered: coveredSet.size,
            total: total
        };
    }, [currentStandard, processes]);

    const radius = 24;
    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference - (coverageStats.percent / 100) * circumference;

    const filteredGroups = useMemo(() => {
        if (!currentStandard) return [];
        if (!search) return currentStandard.groups;

        const term = search.toLowerCase();
        return currentStandard.groups.map(g => {
            const matchingClauses = g.clauses.filter(c => {
                const matchSelf = c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term);
                const matchSub = c.subClauses?.some(s => s.code.toLowerCase().includes(term) || s.title.toLowerCase().includes(term));
                return matchSelf || matchSub;
            });
            return matchingClauses.length > 0 ? { ...g, clauses: matchingClauses } : null;
        }).filter(g => g !== null) as typeof currentStandard.groups;
    }, [currentStandard, search]);


    const handleExportTemplate = () => {
        if (processes.length === 0) { showToast("No processes to export."); return; }
        const templateData = processes.map(p => ({ name: p.name, clauses: Object.keys(p.matrixData) }));
        const blob = new Blob([JSON.stringify(templateData, null, 2)], { type: "application/json" });
        const link = document.createElement("a");
        link.href = URL.createObjectURL(blob);
        link.download = `${cleanFileName(currentStandard.name)}_Plan.json`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showToast("JSON Template exported.");
    };

    const handleExportTxt = () => {
        if (processes.length === 0) { showToast("No data to export."); return; }

        const codeMap: Record<string, string> = {};
        const traverse = (list: Clause[]) => list.forEach(c => {
            codeMap[c.id] = c.code;
            if(c.subClauses) traverse(c.subClauses);
        });
        currentStandard?.groups.forEach(g => traverse(g.clauses));

        let output = "";
        if (exportLang === 'vi') output += `NGÀY XUẤT: ${new Date().toLocaleDateString('vi-VN')}\nTIÊU CHUẨN: ${currentStandard.name}\n====================\n\n`;
        else output += `EXPORT DATE: ${new Date().toLocaleDateString()}\nSTANDARD: ${currentStandard.name}\n====================\n\n`;

        processes.forEach(p => {
            const clauses = Object.keys(p.matrixData)
                .map(id => codeMap[id] || id) 
                .sort((a,b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));

            if (clauses.length > 0) {
                output += `${exportLang === 'vi' ? 'QUY TRÌNH' : 'PROCESS'}: ${p.name}\n`;
                output += `${exportLang === 'vi' ? 'ĐIỀU KHOẢN' : 'SCOPE'}: [${clauses.join(', ')}]\n\n`;
            }
        });

        const blob = new Blob([output], { type: "text/plain" });
        const link = document.createElement("a");
        link.href = URL.createObjectURL(blob);
        link.download = `${cleanFileName(currentStandard.name)}_Scope_${exportLang}.txt`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showToast(`TXT Scope exported (${exportLang.toUpperCase()}).`);
    };

    const handleImportTemplate = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const content = ev.target?.result as string;
                const templateData = JSON.parse(content);
                if (!Array.isArray(templateData)) throw new Error("Invalid format");

                templateData.forEach((item: any) => {
                    if (item.name) addProcess(item.name); 
                });
                showToast(`Imported ${templateData.length} processes structure.`);
            } catch (err) { showToast("Import failed."); }
        };
        reader.readAsText(file);
        e.target.value = '';
    };

    const handleSelectStandardFocus = () => {
        setSidebarOpen(true);
        setTimeout(() => {
            const el = document.getElementById('sidebar-standard-select');
            if (el) {
                el.focus();
                try {
                    if ('showPicker' in el) {
                        (el as any).showPicker();
                    } else {
                        el.click(); 
                    }
                } catch (e) {}
            }
        }, 300);
    };

    if (!currentStandard) return (
        <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/30 dark:bg-slate-900/30 rounded-2xl border border-dashed border-gray-200 dark:border-slate-800 m-4 animate-fade-in-up">
            <Icon name="Book" size={48} className="mb-4 opacity-20"/>
            <p className="font-bold text-slate-500">No Standard Selected</p>
            <button onClick={handleSelectStandardFocus} className="mt-6 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg text-xs font-bold flex items-center gap-2">
                <Icon name="LayoutList" size={16}/> Select Standard
            </button>
        </div>
    );

    return (
        <div className="h-full flex flex-col animate-fade-in-up gap-4 relative">

            {/* Header / Stats */}
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-4 items-center justify-between shrink-0 transition-colors duration-500 ease-fluid">
                <div className="flex items-center gap-6">
                    <div className="relative w-16 h-16 flex items-center justify-center shrink-0">
                        <svg className="transform -rotate-90 w-16 h-16">
                            <circle cx="32" cy="32" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-100 dark:text-slate-800" />
                            <circle cx="32" cy="32" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" strokeDasharray={circumference} strokeDashoffset={strokeDashoffset} className={`${themeConfig.textClass.replace('text-', 'text-opacity-80 ')} transition-all duration-1000 ease-out`} strokeLinecap="round" />
                        </svg>
                        <span className="absolute text-xs font-black text-slate-700 dark:text-white">{coverageStats.percent}%</span>
                    </div>
                    <div className="flex flex-col gap-1">
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">{currentStandard.name}</h3>
                        <p className="text-xs text-slate-500">
                            <span className={`font-bold ${themeConfig.textClass}`}>{coverageStats.covered}</span> of {coverageStats.total} clauses mapped.
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-2 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64 group">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors">
                            <Icon name="Search" size={16}/>
                        </div>
                        <input 
                            ref={searchInputRef}
                            className="w-full pl-10 pr-8 py-2.5 bg-white dark:bg-slate-950 border border-indigo-100 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-800 dark:text-slate-200 placeholder-slate-400 outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"
                            placeholder="Filter clauses..."
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                        />
                        {search && (
                            <button 
                                onClick={() => { setSearch(""); searchInputRef.current?.focus(); }}
                                className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-slate-400 hover:text-red-500 transition-colors"
                            >
                                <Icon name="X" size={14} />
                            </button>
                        )}
                    </div>

                    <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleImportTemplate} />
                    <button onClick={() => fileInputRef.current?.click()} className="p-2.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 shadow-sm active:scale-95 transition-all hover:border-indigo-300 dark:hover:border-slate-600" title="Import Plan">
                        <Icon name="UploadCloud" size={18}/>
                    </button>

                    <button 
                        onClick={handleExportTemplate}
                        className="p-2.5 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 shadow-sm active:scale-95 transition-all hover:border-indigo-300 dark:hover:border-slate-600 flex items-center gap-2"
                        title="Export Template (JSON)"
                    >
                        <Icon name="Grid" size={18}/>
                        <span className="text-xs font-bold hidden md:inline">Template</span>
                    </button>
                </div>
            </div>

            {/* MATRIX CONTAINER - THEMED BORDER TOP */}
            <div className={`flex-1 bg-white dark:bg-slate-900 rounded-2xl border ${themeConfig.borderClass.replace('border-', 'border-opacity-30 border-')} border-t-4 border-t-${themeConfig.borderClass.replace('border-', '')} dark:border-slate-800 overflow-hidden shadow-sm relative flex flex-col transition-colors duration-500 ease-fluid`}>
                {processes.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
                        <p className="mb-4">No processes defined.</p>
                        <div className="p-4 border-2 border-dashed border-indigo-200 dark:border-indigo-900/50 rounded-xl bg-indigo-50 dark:bg-indigo-900/10 text-indigo-500">
                            Create processes in the sidebar to begin planning.
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 overflow-auto custom-scrollbar relative">
                        <table className="w-full text-left border-collapse">
                            <thead className={`${themeConfig.bgSoft.replace('50', '50/80')} dark:bg-slate-950 sticky top-0 z-30 shadow-sm backdrop-blur-sm transition-colors duration-500 ease-fluid`}>
                                <tr>
                                    <th 
                                        className={`p-3 border-b border-r border-gray-200 dark:border-slate-800 sticky left-0 z-40 min-w-[300px] cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors group select-none ${themeConfig.bgSoft}`}
                                        onClick={handleToggleAll}
                                        title={areAllCollapsed ? "Click to Expand All" : "Click to Collapse All"}
                                    >
                                        <div className="flex items-center justify-between">
                                            <span className={`text-[10px] font-bold uppercase tracking-wider transition-colors ${themeConfig.textClass}`}>
                                                Clause Reference
                                            </span>
                                        </div>
                                    </th>
                                    {processes.map(p => (
                                        <th key={p.id} className={`p-3 text-[10px] font-bold uppercase tracking-wider border-b border-gray-200 dark:border-slate-800 min-w-[120px] text-center ${themeConfig.textClass}`}>
                                            <div className="flex flex-col items-center gap-2">
                                                <span className="truncate max-w-[100px]" title={p.name}>{p.name}</span>
                                                <span className="text-[10px] font-bold bg-white dark:bg-slate-800 px-2 py-0.5 rounded-full shadow-sm">
                                                    {Object.keys(p.matrixData).length}
                                                </span>
                                            </div>
                                        </th>
                                    ))}
                                </tr>
                            </thead>

                            <tbody className="divide-y divide-gray-100 dark:divide-slate-800/50">
                                {filteredGroups.map(group => {
                                    const isCollapsed = collapsedGroups.has(group.id);
                                    const groupStyle = getPDCAStyle(group.id); 
                                    const groupFlatList = getGroupClauses(group.clauses);

                                    return (
                                        <React.Fragment key={group.id}>
                                            <tr className={`sticky z-20 hover:brightness-95 transition-all duration-500 ease-fluid ${groupStyle}`}>
                                                <td 
                                                    className="p-2 border-r border-black/5 dark:border-white/5 font-black text-xs uppercase tracking-widest sticky left-0 z-20 bg-inherit shadow-sm cursor-pointer"
                                                    onClick={() => toggleGroupCollapse(group.id)}
                                                >
                                                    <div className="flex items-center justify-between">
                                                        <div className="flex items-center gap-2">
                                                            <Icon name={group.icon} size={14} className="opacity-70"/>
                                                            {group.title}
                                                        </div>
                                                        <Icon name="ChevronDown" size={14} className={`transition-transform duration-300 ${isCollapsed ? '-rotate-90' : 'rotate-0'}`}/>
                                                    </div>
                                                </td>
                                                {processes.map(p => {
                                                    const flatIds: string[] = [];
                                                    const traverse = (list: Clause[]) => list.forEach(c => { flatIds.push(c.id); if(c.subClauses) traverse(c.subClauses); });
                                                    traverse(group.clauses);
                                                    const proc = processes.find(proc => proc.id === p.id);
                                                    const allSelected = proc ? flatIds.every(cid => !!proc.matrixData[cid]) : false;

                                                    return (
                                                        <td key={`group_action_${p.id}_${group.id}`} className="p-2 text-center bg-inherit">
                                                            {!isCollapsed && (
                                                                <button 
                                                                    onClick={(e) => handleGroupToggle(e, p.id, group.clauses)}
                                                                    className="p-1.5 rounded-lg hover:bg-black/10 dark:hover:bg-white/10 transition-colors opacity-70 hover:opacity-100"
                                                                    title={allSelected ? "Deselect Group" : "Select Entire Group"}
                                                                >
                                                                    <Icon name={allSelected ? "CheckSquare" : "Square"} size={16} />
                                                                </button>
                                                            )}
                                                        </td>
                                                    );
                                                })}
                                            </tr>

                                            {!isCollapsed && groupFlatList.map(({ clause, level }) => (
                                                <PlanningRow 
                                                    key={clause.id}
                                                    clause={clause}
                                                    level={level}
                                                    processes={processes}
                                                    onSmartToggle={handleSmartToggle}
                                                />
                                            ))}
                                        </React.Fragment>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <div className="flex-shrink-0 flex flex-row items-center md:justify-end gap-2 md:gap-3 w-full pt-2">
                <div className="flex-1"></div>
                <button 
                    onClick={handleExportTxt} 
                    disabled={processes.length === 0} 
                    className="flex-none md:w-auto px-3 md:px-4 h-[52px] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 whitespace-nowrap dark:shadow-md"
                >
                    <Icon name="FileText" />
                    <span className="hidden md:inline">Export</span>
                    <div className="lang-pill-container">
                        <span onClick={(e) => { e.stopPropagation(); setExportLang('en'); }} className={`lang-pill-btn ${exportLang === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setExportLang('vi'); }} className={`lang-pill-btn ${exportLang === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { DEFAULT_GEMINI_MODEL, DEFAULT_VISION_MODEL, MY_FIXED_KEYS, MODEL_HIERARCHY } from "../constants";
import { PromptRegistry } from "./promptRegistry";
import { VectorStore } from "./vectorStore";
import { PrivacyService } from "./privacyService"; 
